import type { Question } from '@/lib/questions';

export const DAILY_EPOCH = '2026-06-08';

export const dailyQuestions: Question[] = [
  // ── Geography ───────────────────────────────────────────────────────────────
  { id: 'daily-001', question: 'What is the capital of Australia?', answer: 'Canberra', options: ['Canberra', 'Sydney', 'Melbourne', 'Brisbane'], explanation: "Canberra was purpose-built as Australia's capital as a compromise between rival cities Sydney and Melbourne, and officially became the capital in 1913. Sydney is the largest city and the one most people assume is the capital, but Canberra was designed from scratch by American architects Walter Burley Griffin and Marion Mahony Griffin." },
  { id: 'daily-002', question: 'Which country has the most natural lakes in the world?', answer: 'Canada', options: ['Canada', 'Russia', 'Finland', 'USA'], explanation: 'Canada contains approximately 31,752 lakes larger than 3 square kilometres — more than all other countries combined. This is largely a result of glacial activity during the last Ice Age, which carved out depressions across the Canadian Shield that later filled with water.' },
  { id: 'daily-003', question: 'What is the longest river in Africa?', answer: 'Nile', options: ['Nile', 'Congo', 'Niger', 'Zambezi'], explanation: "The Nile stretches approximately 6,650 kilometres, flowing northward through northeastern Africa to the Mediterranean Sea. It was the lifeblood of ancient Egyptian civilization — its annual floods deposited rich silt that made the surrounding land some of the most fertile in the ancient world." },
  { id: 'daily-004', question: 'Which country is home to the most fjords?', answer: 'Norway', options: ['Norway', 'Sweden', 'Iceland', 'Canada'], explanation: "Norway's coastline is deeply indented with thousands of fjords — narrow inlets carved by glaciers during the last Ice Age. The Sognefjord is the longest and deepest, stretching 204 kilometres inland and reaching depths of over 1,300 metres." },
  { id: 'daily-005', question: 'What is the smallest country in the world by area?', answer: 'Vatican City', options: ['Vatican City', 'Monaco', 'San Marino', 'Liechtenstein'], explanation: 'Vatican City covers just 0.44 square kilometres — smaller than most city parks — yet it is an independent nation-state and the headquarters of the Roman Catholic Church. It has its own passport, postal service, bank, and radio station despite having a population of only around 800 people.' },
  { id: 'daily-006', question: 'Which continent has the most countries?', answer: 'Africa', options: ['Africa', 'Asia', 'Europe', 'South America'], explanation: 'Africa has 54 recognized sovereign countries — more than any other continent. The large number of nations reflects the colonial-era partitioning of the continent, which drew borders across ethnic and cultural lines that became the boundaries of independent states after decolonization in the 20th century.' },
  { id: 'daily-007', question: 'What is the capital of Canada?', answer: 'Ottawa', options: ['Ottawa', 'Toronto', 'Vancouver', 'Montreal'], explanation: "Ottawa was chosen as Canada's capital in 1857 by Queen Victoria, partly because its location on the border of Ontario and Quebec made it a political compromise between the English and French populations. Toronto is the largest city, which leads many people to incorrectly assume it is the capital." },
  { id: 'daily-008', question: 'Which ocean is the largest?', answer: 'Pacific', options: ['Pacific', 'Atlantic', 'Indian', 'Arctic'], explanation: "The Pacific Ocean covers approximately 165 million square kilometres — larger than all of Earth's landmasses combined. It contains more than half of the world's ocean water and is home to the Mariana Trench, the deepest point on Earth at nearly 11 kilometres below the surface." },
  { id: 'daily-009', question: 'What is the largest country in the world by area?', answer: 'Russia', options: ['Russia', 'Canada', 'China', 'USA'], explanation: "Russia covers approximately 17.1 million square kilometres — nearly twice the size of the second-largest country, Canada. It spans 11 time zones and contains both the world's largest forest (the Siberian taiga) and Lake Baikal, which holds about 20% of the world's unfrozen surface fresh water." },
  { id: 'daily-010', question: 'Which river flows through Egypt?', answer: 'Nile', options: ['Nile', 'Tigris', 'Euphrates', 'Jordan'], explanation: "The Nile flows northward through Egypt for about 1,545 kilometres before emptying into the Mediterranean Sea via a large delta. Ancient Egyptians called the fertile strip along the Nile 'Kemet' (the Black Land) and the surrounding desert 'Deshret' (the Red Land) — the contrast that defined all Egyptian life." },
  { id: 'daily-011', question: 'What is the capital of Brazil?', answer: 'Brasília', options: ['Brasília', 'Rio de Janeiro', 'São Paulo', 'Salvador'], explanation: "Brasília replaced Rio de Janeiro as Brazil's capital in 1960 and was built from scratch in just 41 months in the country's interior. It was designed by urban planner Lúcio Costa and architect Oscar Niemeyer, and is now a UNESCO World Heritage Site for its modernist architecture and urban design." },
  { id: 'daily-012', question: 'Which country owns Greenland?', answer: 'Denmark', options: ['Denmark', 'Norway', 'Iceland', 'Canada'], explanation: "Greenland is an autonomous territory of Denmark, the world's largest island that is not a continent. Despite its name, about 80% of Greenland is covered by an ice sheet; the island was reportedly given its attractive name by Norse explorer Erik the Red to encourage settlement." },
  { id: 'daily-013', question: 'What is the tallest mountain in Africa?', answer: 'Kilimanjaro', options: ['Kilimanjaro', 'Mount Kenya', 'Rwenzori', 'Atlas'], explanation: "Mount Kilimanjaro in Tanzania rises 5,895 metres above sea level and is the tallest free-standing mountain in the world. Unusually for a mountain at that altitude near the equator, Kilimanjaro has permanent glaciers at its summit, though they have shrunk dramatically due to climate change." },
  { id: 'daily-014', question: 'Which sea separates Europe from Africa?', answer: 'Mediterranean Sea', options: ['Mediterranean Sea', 'Red Sea', 'Caspian Sea', 'Black Sea'], explanation: "The Mediterranean Sea separates Southern Europe from North Africa, with the narrowest point — the Strait of Gibraltar — just 14 kilometres wide. The Mediterranean was the centre of ancient civilizations for millennia; its name comes from the Latin 'mediterra,' meaning 'middle of the earth.'" },
  { id: 'daily-015', question: 'What is the capital of Argentina?', answer: 'Buenos Aires', options: ['Buenos Aires', 'Santiago', 'Lima', 'Bogotá'], explanation: "Buenos Aires is one of the largest cities in South America and serves as Argentina's political and economic centre. Its name means 'fair winds' in Spanish, given by Spanish explorers in the 16th century; the city is often called the 'Paris of South America' for its European-influenced architecture and café culture." },
  { id: 'daily-016', question: 'Which country has the longest coastline?', answer: 'Canada', options: ['Canada', 'Russia', 'Norway', 'Australia'], explanation: "Canada's coastline stretches approximately 202,080 kilometres — the longest of any country in the world, largely because of its thousands of offshore islands and intricate Arctic coastline. If you include all islands, Canada's coastline is so long it would circle the Earth about five times." },
  { id: 'daily-017', question: 'What is the deepest lake in the world?', answer: 'Lake Baikal', options: ['Lake Baikal', 'Lake Tanganyika', 'Caspian Sea', 'Lake Superior'], explanation: "Lake Baikal in Siberia reaches a maximum depth of 1,642 metres and contains approximately 20% of the world's unfrozen surface fresh water. It is also the world's oldest lake at around 25 million years old and is home to the Baikal seal, the only freshwater seal species in the world." },
  { id: 'daily-018', question: 'Which city is known as the City of Canals?', answer: 'Venice', options: ['Venice', 'Amsterdam', 'Bangkok', 'Bruges'], explanation: "Venice is built on 118 small islands in a lagoon in northeastern Italy, connected by about 150 canals instead of streets. The city has been gradually sinking — around 2 millimetres per year — and faces increasing flooding from high tides, a phenomenon known locally as 'acqua alta.'" },
  { id: 'daily-019', question: 'What is the capital of South Korea?', answer: 'Seoul', options: ['Seoul', 'Busan', 'Pyongyang', 'Incheon'], explanation: "Seoul is home to about half of South Korea's entire population and is one of the world's most densely populated cities. It has been the capital of the Korean Peninsula for over 600 years, originally as the capital of the Joseon dynasty, and today it is a global hub for technology, culture, and entertainment." },
  { id: 'daily-020', question: 'Which country is both an island and a continent?', answer: 'Australia', options: ['Australia', 'Greenland', 'New Zealand', 'Indonesia'], explanation: "Australia is the only country that is also classified as a continent, covering the entire Australian tectonic plate. Greenland is larger in some measurements but is considered an island rather than a continent because it sits on the North American tectonic plate." },
  { id: 'daily-021', question: 'What is the largest desert in the world?', answer: 'Antarctic Desert', options: ['Antarctic Desert', 'Sahara', 'Arabian Desert', 'Gobi'], explanation: "A desert is defined by low precipitation, not heat — and Antarctica receives less than 200mm of precipitation per year, making it the world's largest desert at 14 million square kilometres. The Sahara is the largest hot desert at about 9 million square kilometres, which is the answer most people expect." },
  { id: 'daily-022', question: 'Which country is the Colosseum located in?', answer: 'Italy', options: ['Italy', 'Greece', 'Spain', 'Turkey'], explanation: "The Colosseum in Rome was completed in 80 AD and could hold between 50,000 and 80,000 spectators. It is the largest amphitheatre ever built and was used for gladiatorial contests, animal hunts, and public spectacles for about 400 years before falling into disuse after the Western Roman Empire's decline." },
  { id: 'daily-023', question: 'What is the capital of New Zealand?', answer: 'Wellington', options: ['Wellington', 'Auckland', 'Christchurch', 'Hamilton'], explanation: "Wellington is the capital of New Zealand and the southernmost capital city in the world. Auckland is the largest city with about a third of New Zealand's entire population, which leads many people to assume it is the capital — Wellington was chosen partly because of its more central location on the North Island." },
  { id: 'daily-024', question: 'Which mountain range separates Europe from Asia?', answer: 'Ural Mountains', options: ['Ural Mountains', 'Caucasus', 'Carpathians', 'Alps'], explanation: "The Ural Mountains stretch approximately 2,500 kilometres from the Arctic Ocean to the Ural River and have served as the conventional boundary between Europe and Asia since the 18th century. Russia straddles both continents — roughly 77% of its territory is in Asia while about 77% of its population lives in the European part." },
  { id: 'daily-025', question: 'What is the largest lake in Africa?', answer: 'Lake Victoria', options: ['Lake Victoria', 'Lake Tanganyika', 'Lake Malawi', 'Lake Chad'], explanation: "Lake Victoria is the largest lake in Africa by area and the second-largest freshwater lake in the world by surface area, shared by Uganda, Tanzania, and Kenya. It was named by British explorer John Speke in 1858 after Queen Victoria and is the source of the White Nile." },
  { id: 'daily-026', question: 'Which country has the most UNESCO World Heritage Sites?', answer: 'Italy', options: ['Italy', 'China', 'Spain', 'France'], explanation: "Italy has 59 UNESCO World Heritage Sites — more than any other country — reflecting its extraordinary concentration of ancient, medieval, and Renaissance art and architecture. The sites range from the historic centres of Rome, Venice, and Florence to the Amalfi Coast and the prehistoric rock drawings of Valcamonica." },
  { id: 'daily-027', question: 'What is the capital of Saudi Arabia?', answer: 'Riyadh', options: ['Riyadh', 'Jeddah', 'Mecca', 'Medina'], explanation: "Riyadh is the capital and largest city of Saudi Arabia, home to about 7 million people. Despite Mecca and Medina being Islam's two holiest cities — which many might assume would be the capital — Riyadh has been the seat of the Saudi royal family and government since the country's founding." },
  { id: 'daily-028', question: 'Which strait connects the Atlantic and Pacific Oceans?', answer: 'Strait of Magellan', options: ['Strait of Magellan', 'Drake Passage', 'Strait of Gibraltar', 'Bering Strait'], explanation: "The Strait of Magellan at the southern tip of South America is a navigable sea route connecting the Atlantic and Pacific Oceans, named after Ferdinand Magellan who first navigated it in 1520. The Drake Passage is a wider open-ocean route south of Cape Horn, not technically a strait." },
  { id: 'daily-029', question: 'What is the highest waterfall in the world?', answer: 'Angel Falls', options: ['Angel Falls', 'Niagara Falls', 'Victoria Falls', 'Iguazu Falls'], explanation: "Angel Falls in Venezuela plunges 979 metres — nearly 20 times the height of Niagara Falls. It was named after American aviator Jimmy Angel, who became the first to fly over the falls in 1933; the local indigenous name is 'Kerepakupai Merú,' meaning 'waterfall of the deepest place.'" },
  { id: 'daily-030', question: 'Which country is home to the Amazon Rainforest mostly?', answer: 'Brazil', options: ['Brazil', 'Colombia', 'Peru', 'Venezuela'], explanation: "About 60% of the Amazon Rainforest lies within Brazil, with the remainder spread across eight other South American countries. The Amazon produces roughly 20% of the world's oxygen and is home to an estimated 10% of all species on Earth, earning it the nickname 'the lungs of the planet.'" },

  // ── History ─────────────────────────────────────────────────────────────────
  { id: 'daily-031', question: 'In which year did World War II end?', answer: '1945', options: ['1945', '1944', '1946', '1943'], explanation: "World War II ended in 1945 with Germany's surrender on May 8 (V-E Day) and Japan's surrender on September 2 (V-J Day) following the atomic bombings of Hiroshima and Nagasaki. It was the deadliest conflict in human history, with an estimated 70–85 million deaths including both military and civilian casualties." },
  { id: 'daily-032', question: 'Who was the first person to walk on the Moon?', answer: 'Neil Armstrong', options: ['Neil Armstrong', 'Buzz Aldrin', 'Yuri Gagarin', 'Alan Shepard'], explanation: "Neil Armstrong stepped onto the lunar surface on July 20, 1969, during the Apollo 11 mission, uttering 'That's one small step for man, one giant leap for mankind.' Buzz Aldrin followed minutes later, while Michael Collins orbited above in the command module — often called the 'forgotten astronaut.'" },
  { id: 'daily-033', question: 'Which empire was ruled by Julius Caesar?', answer: 'Roman Empire', options: ['Roman Empire', 'Greek Empire', 'Ottoman Empire', 'Byzantine Empire'], explanation: "Julius Caesar was a Roman general and statesman who played a critical role in transforming the Roman Republic into the Roman Empire. Technically, Caesar ruled the Republic — not the Empire — as he was never officially emperor; it was his adopted son Octavian (Augustus) who became the first true Roman Emperor after Caesar's assassination in 44 BC." },
  { id: 'daily-034', question: 'In which year did the Berlin Wall fall?', answer: '1989', options: ['1989', '1991', '1987', '1985'], explanation: "The Berlin Wall fell on November 9, 1989, when the East German government announced that citizens could cross freely — a live broadcast misunderstanding that triggered an immediate crowd at the checkpoints. The Wall had divided East and West Berlin since 1961 and had become the most powerful symbol of the Iron Curtain." },
  { id: 'daily-035', question: 'Who was the first President of the United States?', answer: 'George Washington', options: ['George Washington', 'John Adams', 'Thomas Jefferson', 'Benjamin Franklin'], explanation: "George Washington was unanimously elected the first US President in 1789 and served two terms before voluntarily stepping down — establishing the two-term precedent that lasted until FDR. His decision to relinquish power was so remarkable that King George III reportedly said it would make him 'the greatest man in the world.'" },
  { id: 'daily-036', question: 'Which country launched the first artificial satellite, Sputnik?', answer: 'Soviet Union', options: ['Soviet Union', 'USA', 'Germany', 'France'], explanation: "The Soviet Union launched Sputnik 1 on October 4, 1957, the world's first artificial satellite — a polished metal sphere that orbited Earth every 96 minutes broadcasting a radio beep. Its launch shocked the US into the Space Race and ultimately led to NASA's creation in 1958 and the Apollo Moon program." },
  { id: 'daily-037', question: 'In which year did the Titanic sink?', answer: '1912', options: ['1912', '1910', '1914', '1908'], explanation: "The RMS Titanic sank on April 15, 1912 after striking an iceberg on her maiden voyage from Southampton to New York. Of the 2,224 people aboard, more than 1,500 died — largely due to an insufficient number of lifeboats, which could only carry about half the ship's capacity." },
  { id: 'daily-038', question: 'Who wrote the Declaration of Independence?', answer: 'Thomas Jefferson', options: ['Thomas Jefferson', 'George Washington', 'Benjamin Franklin', 'John Adams'], explanation: "Thomas Jefferson was the primary author of the Declaration of Independence, drafted in 1776. Benjamin Franklin and John Adams made some revisions, but Jefferson wrote the core text in about two weeks — including the famous line 'all men are created equal,' though Jefferson himself owned enslaved people throughout his life." },
  { id: 'daily-039', question: 'Which ancient wonder was located in Alexandria, Egypt?', answer: 'Lighthouse of Alexandria', options: ['Lighthouse of Alexandria', 'Library of Alexandria', 'Colossus of Rhodes', 'Hanging Gardens'], explanation: "The Lighthouse of Alexandria (Pharos of Alexandria) was built around 280 BC on a small island and stood approximately 100–130 metres tall — one of the tallest man-made structures in the ancient world. It guided ships into Alexandria's harbour for over 1,500 years before being destroyed by earthquakes in the 14th century." },
  { id: 'daily-040', question: 'In which year did the French Revolution begin?', answer: '1789', options: ['1789', '1776', '1799', '1804'], explanation: "The French Revolution began in 1789 with the storming of the Bastille on July 14, a day still celebrated as France's national holiday (Bastille Day). The revolution dismantled the monarchy and aristocracy, establishing the principles of liberty, equality, and fraternity that influenced democratic movements worldwide." },
  { id: 'daily-041', question: 'Who was the Egyptian pharaoh associated with the famous golden mask?', answer: 'Tutankhamun', options: ['Tutankhamun', 'Ramesses II', 'Cleopatra', 'Nefertiti'], explanation: "Tutankhamun's tomb was discovered nearly intact by Howard Carter in 1922, making it one of archaeology's greatest finds. He died at around 18 years old, and while he was a relatively minor pharaoh during his reign, the spectacular treasures in his tomb — including his golden death mask — made him the most famous of all Egyptian rulers." },
  { id: 'daily-042', question: 'Which war was fought between the North and South of the USA?', answer: 'Civil War', options: ['Civil War', 'Revolutionary War', 'War of 1812', 'Mexican-American War'], explanation: "The American Civil War (1861–1865) was fought between the Union (Northern states) and the Confederacy (Southern states that seceded), primarily over slavery and states' rights. It remains the deadliest war in American history with an estimated 620,000–750,000 military deaths, more than all other American wars combined." },
  { id: 'daily-043', question: 'Who was the first woman to win a Nobel Prize?', answer: 'Marie Curie', options: ['Marie Curie', 'Rosalind Franklin', 'Florence Nightingale', 'Ada Lovelace'], explanation: "Marie Curie won the Nobel Prize in Physics in 1903 (shared with her husband Pierre and Henri Becquerel) and then the Nobel Prize in Chemistry in 1911 — making her the first person to win Nobel Prizes in two different sciences. She discovered polonium and radium, and her research on radioactivity was foundational to modern nuclear physics." },
  { id: 'daily-044', question: 'In which year did the Soviet Union collapse?', answer: '1991', options: ['1991', '1989', '1993', '1985'], explanation: "The Soviet Union officially dissolved on December 25, 1991, when Mikhail Gorbachev resigned and the USSR was replaced by 15 independent states. The collapse followed years of economic stagnation and was accelerated by Gorbachev's reforms (glasnost and perestroika) and a failed coup attempt by hardliners in August 1991." },
  { id: 'daily-045', question: 'Which explorer is credited with circumnavigating the globe first?', answer: 'Ferdinand Magellan', options: ['Ferdinand Magellan', 'Christopher Columbus', 'Vasco da Gama', 'James Cook'], explanation: "Ferdinand Magellan led the first expedition to circumnavigate Earth (1519–1522), though he died in the Philippines before completing the journey. His navigator Juan Sebastián Elcano brought the one surviving ship back to Spain — of the original 270 men, only 18 completed the entire voyage." },
  { id: 'daily-046', question: 'What was the name of the ship Charles Darwin sailed on?', answer: 'HMS Beagle', options: ['HMS Beagle', 'HMS Victory', 'Endeavour', 'HMS Bounty'], explanation: "Darwin sailed on HMS Beagle from 1831 to 1836 on a surveying expedition that took him to South America, the Galapagos Islands, Australia, and Africa. His observations of wildlife — particularly the distinct finch species across Galapagos islands — were instrumental in developing his theory of evolution by natural selection." },
  { id: 'daily-047', question: 'In which city was the Magna Carta signed?', answer: 'Runnymede', options: ['Runnymede', 'London', 'Canterbury', 'Winchester'], explanation: "The Magna Carta was sealed by King John at Runnymede, a meadow beside the River Thames near Windsor, on June 15, 1215 — not technically a 'city' but a specific location. It was a landmark document limiting the king's power and establishing that everyone, including the king, was subject to the law." },
  { id: 'daily-048', question: 'Who built the Great Wall of China?', answer: 'Emperor Qin Shi Huang', options: ['Emperor Qin Shi Huang', 'Kublai Khan', 'Emperor Han Wudi', 'Genghis Khan'], explanation: "Emperor Qin Shi Huang initiated the Great Wall around 221 BC by connecting existing walls built by various states. The wall was significantly extended during the Ming Dynasty (1368–1644), which built most of the wall tourists see today — the original Qin wall has largely crumbled." },
  { id: 'daily-049', question: 'In which year did humans first land on the Moon?', answer: '1969', options: ['1969', '1967', '1971', '1965'], explanation: "Apollo 11 landed on the Moon on July 20, 1969, with Neil Armstrong and Buzz Aldrin spending about 2.5 hours on the lunar surface. The mission fulfilled President Kennedy's 1961 challenge to land a man on the Moon before the end of the decade, with just five months to spare." },
  { id: 'daily-050', question: 'Which country was Nelson Mandela president of?', answer: 'South Africa', options: ['South Africa', 'Zimbabwe', 'Kenya', 'Nigeria'], explanation: "Nelson Mandela became South Africa's first Black president in 1994 after the end of apartheid — the system of institutionalized racial segregation. He had spent 27 years in prison, primarily on Robben Island, before his release in 1990; his willingness to pursue reconciliation rather than retribution after taking power defined his presidency." },
  { id: 'daily-051', question: 'What was the name of the first nuclear bomb dropped on Japan?', answer: 'Little Boy', options: ['Little Boy', 'Fat Man', 'Trinity', 'Big Bang'], explanation: "'Little Boy' was a uranium bomb dropped on Hiroshima on August 6, 1945, killing an estimated 80,000 people instantly with tens of thousands more dying from radiation. Three days later, 'Fat Man' — a plutonium bomb — was dropped on Nagasaki; 'Trinity' was the code name for the first-ever nuclear test in New Mexico." },
  { id: 'daily-052', question: 'Who was the British Prime Minister during most of World War II?', answer: 'Winston Churchill', options: ['Winston Churchill', 'Neville Chamberlain', 'Clement Attlee', 'Anthony Eden'], explanation: "Winston Churchill became Prime Minister in May 1940, replacing Neville Chamberlain who had pursued the failed appeasement policy with Hitler. Churchill led Britain through its darkest years and his wartime speeches — including 'We shall fight on the beaches' — became some of the most celebrated rhetoric in the English language." },
  { id: 'daily-053', question: 'In which year did the American Civil War end?', answer: '1865', options: ['1865', '1863', '1867', '1861'], explanation: "The American Civil War ended in April 1865 when Confederate General Robert E. Lee surrendered to Ulysses S. Grant at Appomattox Court House, Virginia. President Lincoln was assassinated just five days later, and the war's aftermath — Reconstruction — reshaped American society for decades." },
  { id: 'daily-054', question: 'Which ancient civilization built Machu Picchu?', answer: 'Inca', options: ['Inca', 'Aztec', 'Maya', 'Olmec'], explanation: "Machu Picchu was built by the Inca Empire around 1450 AD at an altitude of 2,430 metres in the Peruvian Andes. It was abandoned about 100 years later during the Spanish conquest and was largely unknown to the outside world until American historian Hiram Bingham III brought it to international attention in 1911." },
  { id: 'daily-055', question: 'Who was the first Emperor of Rome?', answer: 'Augustus', options: ['Augustus', 'Julius Caesar', 'Nero', 'Caligula'], explanation: "Augustus (born Octavian) became Rome's first emperor in 27 BC after defeating Mark Antony and Cleopatra. Julius Caesar, his great-uncle and adoptive father, is often assumed to be the first emperor but technically held the title of dictator — Augustus was careful to cloak his absolute power in republican forms to avoid Caesar's fate." },
  { id: 'daily-056', question: 'Which country did Napoleon Bonaparte come from?', answer: 'France', options: ['France', 'Corsica', 'Italy', 'Spain'], explanation: "Napoleon was born in Corsica in 1769, just a year after France purchased the island from Genoa — making him technically French by a narrow margin of history. He rose through the ranks during the French Revolution and became Emperor of the French in 1804, conquering most of continental Europe before his final defeat at Waterloo in 1815." },
  { id: 'daily-057', question: 'In which year was the United Nations founded?', answer: '1945', options: ['1945', '1919', '1950', '1939'], explanation: "The United Nations was founded on October 24, 1945 — now celebrated as UN Day — with 51 original member states. It replaced the League of Nations, which had failed to prevent World War II; the UN's founding charter was signed in San Francisco in June 1945 before the war had even formally ended." },
  { id: 'daily-058', question: 'Who assassinated Archduke Franz Ferdinand, triggering WWI?', answer: 'Gavrilo Princip', options: ['Gavrilo Princip', 'Leon Czolgosz', 'John Wilkes Booth', 'Mehmed Talat'], explanation: "Gavrilo Princip, a Bosnian Serb nationalist, shot Archduke Franz Ferdinand of Austria-Hungary on June 28, 1914 in Sarajevo. The assassination itself was almost accidental — an earlier bomb attack had failed, and Princip encountered the Archduke's motorcade by chance after it made a wrong turn near a deli where he was eating." },
  { id: 'daily-059', question: 'Which dynasty built the Forbidden City in Beijing?', answer: 'Ming Dynasty', options: ['Ming Dynasty', 'Qing Dynasty', 'Han Dynasty', 'Tang Dynasty'], explanation: "The Forbidden City was built between 1406 and 1420 during the reign of the Yongle Emperor of the Ming Dynasty. It served as the imperial palace for 24 emperors across both the Ming and Qing dynasties until 1912, and was so named because ordinary people were forbidden from entering without special permission." },
  { id: 'daily-060', question: 'In which year did India gain independence from Britain?', answer: '1947', options: ['1947', '1945', '1950', '1942'], explanation: "India gained independence from British rule on August 15, 1947, the same day Pakistan was created as a separate nation through the Partition of India. The partition caused one of the largest mass migrations in history — an estimated 10–20 million people displaced — and significant communal violence with hundreds of thousands killed." },

  // ── Science & Nature ────────────────────────────────────────────────────────
  { id: 'daily-061', question: 'What is the chemical symbol for gold?', answer: 'Au', options: ['Au', 'Ag', 'Fe', 'Cu'], explanation: "Gold's symbol Au comes from the Latin word 'aurum.' Many elements have symbols derived from their Latin names rather than their English names — including Fe (iron, from 'ferrum'), Ag (silver, from 'argentum'), and Cu (copper, from 'cuprum')." },
  { id: 'daily-062', question: 'How many bones are in the adult human body?', answer: '206', options: ['206', '213', '198', '220'], explanation: "Adult humans have 206 bones, but babies are born with around 270–300 bones — many of which fuse together during childhood and adolescence. The process of bone fusion is largely complete by the mid-20s, which is why doctors use bone density and fusion as indicators of biological age." },
  { id: 'daily-063', question: 'What planet is known as the Red Planet?', answer: 'Mars', options: ['Mars', 'Venus', 'Jupiter', 'Saturn'], explanation: "Mars appears red due to iron oxide (rust) on its surface and in its thin atmosphere. It has the largest volcano in the solar system (Olympus Mons, three times the height of Everest) and the longest canyon (Valles Marineris, which would stretch across the entire United States)." },
  { id: 'daily-064', question: 'What is the speed of light in a vacuum (approximately)?', answer: '300,000 km/s', options: ['300,000 km/s', '150,000 km/s', '500,000 km/s', '1,000,000 km/s'], explanation: "Light travels at approximately 299,792 kilometres per second in a vacuum — rounded to 300,000 km/s. This speed is a fundamental constant of the universe (c) and forms the basis of Einstein's special relativity; nothing with mass can reach or exceed this speed, which is why interstellar travel remains so challenging." },
  { id: 'daily-065', question: 'Which element has the atomic number 1?', answer: 'Hydrogen', options: ['Hydrogen', 'Helium', 'Lithium', 'Carbon'], explanation: "Hydrogen has one proton and is the lightest and most abundant element in the universe, making up about 75% of all normal matter by mass. It is the primary fuel for stars — the Sun converts around 600 million tonnes of hydrogen into helium every second through nuclear fusion." },
  { id: 'daily-066', question: 'What is the powerhouse of the cell?', answer: 'Mitochondria', options: ['Mitochondria', 'Nucleus', 'Ribosome', 'Chloroplast'], explanation: "Mitochondria produce the cell's energy currency, ATP (adenosine triphosphate), through cellular respiration. They have their own DNA separate from the cell's nucleus — evidence that they were once free-living bacteria that were absorbed by larger cells in an ancient symbiotic relationship." },
  { id: 'daily-067', question: 'How many planets are in our solar system?', answer: '8', options: ['8', '9', '7', '10'], explanation: "The solar system has 8 planets after Pluto was reclassified as a 'dwarf planet' by the International Astronomical Union in 2006. The decision was controversial — Pluto's discoverer Clyde Tombaugh had died the year before, and many astronomers and the general public still resist the demotion." },
  { id: 'daily-068', question: 'What gas do plants absorb from the atmosphere?', answer: 'Carbon dioxide', options: ['Carbon dioxide', 'Oxygen', 'Nitrogen', 'Hydrogen'], explanation: "Plants absorb carbon dioxide (CO₂) during photosynthesis, using sunlight to convert it and water into glucose and oxygen. This process is the foundation of nearly all food chains on Earth and is why forests and oceans are critical carbon sinks that help regulate the planet's climate." },
  { id: 'daily-069', question: 'What is the hardest natural substance on Earth?', answer: 'Diamond', options: ['Diamond', 'Graphite', 'Quartz', 'Titanium'], explanation: "Diamond scores 10 on the Mohs hardness scale — the maximum — and can only be scratched by another diamond. Remarkably, diamond and graphite (pencil lead) are both made entirely of carbon; the difference is in how the carbon atoms are arranged, giving diamond its extraordinary hardness and graphite its softness." },
  { id: 'daily-070', question: 'Which organ produces insulin?', answer: 'Pancreas', options: ['Pancreas', 'Liver', 'Kidney', 'Thyroid'], explanation: "The pancreas produces insulin in clusters of cells called the islets of Langerhans. Insulin regulates blood sugar by allowing cells to absorb glucose; in type 1 diabetes the immune system destroys these cells, while in type 2 diabetes the body becomes resistant to insulin's effects." },
  { id: 'daily-071', question: 'What is the most abundant gas in Earth\'s atmosphere?', answer: 'Nitrogen', options: ['Nitrogen', 'Oxygen', 'Carbon dioxide', 'Argon'], explanation: "Earth's atmosphere is about 78% nitrogen, 21% oxygen, and 1% other gases (mainly argon and carbon dioxide). Most organisms cannot use atmospheric nitrogen directly — it must be 'fixed' into usable compounds by bacteria or lightning, making nitrogen-fixing bacteria some of the most important organisms on Earth." },
  { id: 'daily-072', question: 'How many chromosomes do humans have?', answer: '46', options: ['46', '48', '44', '23'], explanation: "Humans have 46 chromosomes arranged in 23 pairs — one set of 23 from each parent. Chimpanzees have 48 chromosomes; it is believed two ancestral primate chromosomes fused to form human chromosome 2, which still carries evidence of this ancient merger in its genetic structure." },
  { id: 'daily-073', question: 'What force keeps planets in orbit around the Sun?', answer: 'Gravity', options: ['Gravity', 'Magnetism', 'Nuclear force', 'Friction'], explanation: "Gravity — the attractive force between masses — keeps planets in elliptical orbits around the Sun. Isaac Newton formulated the law of universal gravitation in 1687, and Albert Einstein later reframed gravity not as a force but as a curvature of spacetime caused by mass, in his general theory of relativity (1915)." },
  { id: 'daily-074', question: 'What is the chemical formula for water?', answer: 'H₂O', options: ['H₂O', 'CO₂', 'NaCl', 'H₂SO₄'], explanation: "Water (H₂O) consists of two hydrogen atoms bonded to one oxygen atom. Its unique properties — including its high surface tension, ability to dissolve many substances, and the fact that ice is less dense than liquid water — make it essential to all known life and unusual among common substances." },
  { id: 'daily-075', question: 'Which scientist developed the theory of relativity?', answer: 'Albert Einstein', options: ['Albert Einstein', 'Isaac Newton', 'Niels Bohr', 'Max Planck'], explanation: "Albert Einstein published his special theory of relativity in 1905 and his general theory in 1915. His famous equation E=mc² describes the equivalence of mass and energy, and has been confirmed experimentally countless times — including by the precision of GPS satellites, which must account for relativistic effects to remain accurate." },
  { id: 'daily-076', question: 'What is the largest organ of the human body?', answer: 'Skin', options: ['Skin', 'Liver', 'Lungs', 'Brain'], explanation: "Skin is the body's largest organ, covering about 2 square metres in an average adult and accounting for roughly 15% of total body weight. It serves as the body's primary barrier against pathogens, regulates temperature through sweating and blood vessel dilation, and contains sensory receptors for touch, pressure, and pain." },
  { id: 'daily-077', question: 'Which planet has the most moons?', answer: 'Saturn', options: ['Saturn', 'Jupiter', 'Uranus', 'Neptune'], explanation: "Saturn has 146 confirmed moons — the most of any planet — after astronomers discovered a large batch of new small moons in 2023. Jupiter held the record for a long time with 95 moons; Saturn's largest moon, Titan, has a thick atmosphere and liquid methane lakes on its surface." },
  { id: 'daily-078', question: 'What is the boiling point of water at sea level in Celsius?', answer: '100°C', options: ['100°C', '90°C', '110°C', '212°C'], explanation: "Water boils at 100°C (212°F) at standard sea-level atmospheric pressure. At higher altitudes, where atmospheric pressure is lower, water boils at a lower temperature — on Mount Everest's summit, water boils at around 70°C, which is why food takes longer to cook at high altitude." },
  { id: 'daily-079', question: 'What type of animal is a Komodo dragon?', answer: 'Lizard', options: ['Lizard', 'Crocodilian', 'Snake', 'Turtle'], explanation: "The Komodo dragon is the world's largest living lizard, reaching up to 3 metres in length and 70 kg in weight. Long thought to kill prey with bacteria-laden saliva, research has since shown that Komodo dragons actually have venom glands that produce anticoagulant compounds, preventing prey's blood from clotting." },
  { id: 'daily-080', question: 'Which vitamin does sunlight help the body produce?', answer: 'Vitamin D', options: ['Vitamin D', 'Vitamin C', 'Vitamin A', 'Vitamin B12'], explanation: "Ultraviolet B (UVB) radiation from sunlight triggers the synthesis of vitamin D in the skin from a cholesterol-derived compound. Vitamin D is essential for calcium absorption and bone health; deficiency was historically common in northern latitudes during winter, causing the bone disease rickets." },
  { id: 'daily-081', question: 'What is the name of the process by which plants make food?', answer: 'Photosynthesis', options: ['Photosynthesis', 'Respiration', 'Osmosis', 'Fermentation'], explanation: "Photosynthesis converts light energy, water, and carbon dioxide into glucose and oxygen, occurring mainly in chloroplasts — the organelles that give plants their green colour via the pigment chlorophyll. The process produces virtually all the oxygen in Earth's atmosphere and all the organic matter at the base of food chains." },
  { id: 'daily-082', question: 'How many hearts does an octopus have?', answer: '3', options: ['3', '1', '2', '4'], explanation: "An octopus has three hearts: two branchial hearts pump blood through the gills, while the systemic heart pumps oxygenated blood to the rest of the body. When an octopus swims, the systemic heart stops beating, which is why they prefer crawling — swimming exhausts them quickly." },
  { id: 'daily-083', question: 'What is the closest star to Earth besides the Sun?', answer: 'Proxima Centauri', options: ['Proxima Centauri', 'Alpha Centauri A', 'Sirius', 'Betelgeuse'], explanation: "Proxima Centauri is approximately 4.24 light-years from Earth — the closest known star to our Sun. It is a red dwarf and part of the Alpha Centauri triple star system; it hosts at least one planet, Proxima b, in what appears to be the habitable zone, making it one of the most studied nearby stars." },
  { id: 'daily-084', question: 'Which blood type is known as the universal donor?', answer: 'O negative', options: ['O negative', 'AB positive', 'A positive', 'O positive'], explanation: "O negative blood can be given to patients of any blood type in emergencies because it lacks the A, B, and Rh antigens that can trigger immune rejection. AB positive is the 'universal recipient' — people with this blood type can receive blood of any type. Only about 7% of people have O negative blood." },
  { id: 'daily-085', question: 'What is the chemical symbol for iron?', answer: 'Fe', options: ['Fe', 'Ir', 'In', 'I'], explanation: "Iron's symbol Fe comes from the Latin 'ferrum.' Iron is the most abundant element on Earth by mass and forms much of the planet's inner and outer core; it is also the heaviest element created in significant quantities by stellar fusion — elements heavier than iron are forged in supernova explosions." },
  { id: 'daily-086', question: 'What is the name of the galaxy that contains our solar system?', answer: 'Milky Way', options: ['Milky Way', 'Andromeda', 'Triangulum', 'Sombrero'], explanation: "The Milky Way is a barred spiral galaxy containing an estimated 100–400 billion stars; our solar system sits about 26,000 light-years from the galactic centre. The Andromeda galaxy is our nearest large galactic neighbour and is on a collision course with the Milky Way — expected to merge in about 4.5 billion years." },
  { id: 'daily-087', question: 'How long does light from the Sun take to reach Earth?', answer: '8 minutes', options: ['8 minutes', '1 minute', '1 hour', '24 hours'], explanation: "Light from the Sun takes approximately 8 minutes and 20 seconds to reach Earth, travelling about 150 million kilometres. This means that when you look at the Sun, you are seeing it as it was 8 minutes ago — and when astronomers observe distant stars or galaxies, they are literally looking back in time." },
  { id: 'daily-088', question: 'What is the most common element in the universe?', answer: 'Hydrogen', options: ['Hydrogen', 'Helium', 'Oxygen', 'Carbon'], explanation: "Hydrogen makes up about 75% of all normal (baryonic) matter in the universe by mass, with helium making up most of the rest. Both were created in the first few minutes after the Big Bang; all heavier elements were forged later inside stars or during supernova explosions." },
  { id: 'daily-089', question: 'Which part of the brain controls balance?', answer: 'Cerebellum', options: ['Cerebellum', 'Cerebrum', 'Brain stem', 'Hippocampus'], explanation: "The cerebellum sits at the back of the brain and coordinates muscle movements, balance, and fine motor control. Though it makes up only about 10% of the brain's volume, it contains more than 50% of the brain's neurons — reflecting the enormous computational complexity of coordinating smooth, precise movements." },
  { id: 'daily-090', question: 'What is the unit of electrical resistance?', answer: 'Ohm', options: ['Ohm', 'Volt', 'Ampere', 'Watt'], explanation: "The ohm (Ω) is named after German physicist Georg Simon Ohm, who formulated Ohm's Law: voltage equals current multiplied by resistance (V = IR). The volt is the unit of electrical potential, the ampere (amp) is the unit of current, and the watt is the unit of power." },

  // ── Pop Culture – Movies ─────────────────────────────────────────────────────
  { id: 'daily-091', question: 'Which film won the first Academy Award for Best Picture?', answer: 'Wings', options: ['Wings', 'Sunrise', 'The Jazz Singer', 'Ben-Hur'], explanation: "Wings (1927) won Best Picture at the inaugural Academy Awards ceremony held in 1929, covering films from 1927–28. It remains the only silent film to win Best Picture; there was also a separate award that year for 'Unique and Artistic Picture' given to Sunrise — sometimes causing confusion." },
  { id: 'daily-092', question: 'Who directed Jurassic Park?', answer: 'Steven Spielberg', options: ['Steven Spielberg', 'James Cameron', 'George Lucas', 'Peter Jackson'], explanation: "Steven Spielberg directed Jurassic Park (1993), which used groundbreaking CGI combined with animatronic dinosaurs to create the most realistic prehistoric animals ever seen on screen. Industrial Light & Magic's digital effects were so revolutionary that the film effectively launched the era of CGI-driven blockbusters." },
  { id: 'daily-093', question: 'What is the highest-grossing film of all time (adjusted for inflation)?', answer: 'Gone with the Wind', options: ['Gone with the Wind', 'Avatar', 'Titanic', 'Avengers: Endgame'], explanation: "Gone with the Wind (1939) remains the highest-grossing film ever when ticket prices are adjusted for inflation, with estimated inflation-adjusted earnings well over $3 billion. Avatar is the highest-grossing by unadjusted modern box office, but accounting for decades of higher ticket volumes and prices changes the ranking dramatically." },
  { id: 'daily-094', question: 'In The Lion King, what is Simba\'s father\'s name?', answer: 'Mufasa', options: ['Mufasa', 'Scar', 'Rafiki', 'Simba'], explanation: "Mufasa, voiced by James Earl Jones in the 1994 original, is one of Disney's most beloved father figures — his death scene remains one of the most emotionally devastating in animation history. Jones reprised the role in the 2019 remake, connecting both versions of the film." },
  { id: 'daily-095', question: 'Which actor played Iron Man in the MCU?', answer: 'Robert Downey Jr.', options: ['Robert Downey Jr.', 'Chris Evans', 'Chris Hemsworth', 'Mark Ruffalo'], explanation: "Robert Downey Jr.'s casting as Tony Stark in Iron Man (2008) was considered a significant gamble given his career struggles at the time. The film launched the entire Marvel Cinematic Universe; his arc ended with his self-sacrifice in Avengers: Endgame (2019), the highest-grossing superhero film ever made." },
  { id: 'daily-096', question: 'What year was the original Star Wars released?', answer: '1977', options: ['1977', '1980', '1975', '1979'], explanation: "Star Wars (later subtitled A New Hope) was released on May 25, 1977, and became a cultural phenomenon that transformed the film industry. It popularised the summer blockbuster model, pioneered digital sound in theatres, and launched one of the most lucrative entertainment franchises in history." },
  { id: 'daily-097', question: 'Which film features the quote "You\'re gonna need a bigger boat"?', answer: 'Jaws', options: ['Jaws', 'The Deep', 'Titanic', 'Cast Away'], explanation: "The line was improvised by Roy Scheider on the set of Jaws (1975) and became one of cinema's most quoted phrases. Jaws is widely credited as the first modern summer blockbuster; its success, followed by Star Wars in 1977, permanently shifted Hollywood's release strategy toward big-budget summer tentpoles." },
  { id: 'daily-098', question: 'Who voiced Woody in Toy Story?', answer: 'Tom Hanks', options: ['Tom Hanks', 'Tim Allen', 'Billy Crystal', 'John Goodman'], explanation: "Tom Hanks voiced Woody the cowboy in all four Toy Story films (1995, 1999, 2010, 2019). Tim Allen voiced Buzz Lightyear; both actors were cast partly to create a comedic contrast — Hanks' warmth against Allen's pomposity — that drove the first film's buddy dynamic." },
  { id: 'daily-099', question: 'Which film is set in the fictional African country Wakanda?', answer: 'Black Panther', options: ['Black Panther', 'Thor', 'Doctor Strange', 'Captain America'], explanation: "Black Panther (2018) was the first MCU film with a primarily Black cast and became the first superhero film nominated for the Academy Award for Best Picture. Wakanda's design drew on real African architecture, textiles, and cultures across the continent rather than defaulting to stereotypical depictions." },
  { id: 'daily-100', question: 'What is the name of the toy store in the movie Big?', answer: 'FAO Schwarz', options: ['FAO Schwarz', 'Toys R Us', 'Zoltar\'s', 'MacMillan'], explanation: "FAO Schwarz, one of America's oldest and most famous toy stores, hosted the iconic floor piano scene in Big (1988) where Tom Hanks and Robert Loggia dance out 'Heart and Soul' and 'Chopsticks.' The scene became so beloved that FAO Schwarz installed a permanent floor piano for decades." },
  { id: 'daily-101', question: 'Which country produces the most films annually?', answer: 'India', options: ['India', 'USA', 'China', 'Nigeria'], explanation: "India's film industry ('Bollywood' is just one of several regional industries) produces around 1,500–2,000 films per year — more than any other country. Hollywood produces around 700–800. Indian cinema is extraordinarily diverse, with major industries producing films in Hindi, Tamil, Telugu, Malayalam, and many other languages." },
  { id: 'daily-102', question: 'In which film does a character say "I\'ll be back"?', answer: 'The Terminator', options: ['The Terminator', 'Predator', 'RoboCop', 'Total Recall'], explanation: "Arnold Schwarzenegger delivers the line in The Terminator (1984), directed by James Cameron. Schwarzenegger reportedly wanted to say 'I will be back' because the contraction sounded grammatically wrong for a machine, but Cameron insisted — and the naturalness of the contraction made it more memorably menacing." },
  { id: 'daily-103', question: 'Who plays Katniss Everdeen in The Hunger Games?', answer: 'Jennifer Lawrence', options: ['Jennifer Lawrence', 'Emma Watson', 'Shailene Woodley', 'Chloe Grace Moretz'], explanation: "Jennifer Lawrence was 22 when the first Hunger Games film premiered in 2012, having already received an Oscar nomination for Winter's Bone (2010). She won the Best Actress Oscar for Silver Linings Playbook (2012) while still filming Hunger Games sequels, making her one of the most prominent young actresses of the decade." },
  { id: 'daily-104', question: 'Which animated film features the song "Let It Go"?', answer: 'Frozen', options: ['Frozen', 'Tangled', 'Brave', 'Moana'], explanation: "'Let It Go' from Frozen (2013) won the Academy Award for Best Original Song and was performed by Idina Menzel, who voices Elsa. The film became the highest-grossing animated film of all time upon its release and spawned one of Disney's most successful franchises, including a 2019 sequel." },
  { id: 'daily-105', question: 'What is the name of the sunken ship in Titanic?', answer: 'RMS Titanic', options: ['RMS Titanic', 'SS Titanic', 'HMS Titanic', 'MV Titanic'], explanation: "The ship's full name was RMS Titanic — 'RMS' standing for Royal Mail Ship, reflecting that it was contracted to carry British Royal Mail. The designation 'HMS' is reserved for Royal Navy vessels, and 'SS' (steam ship) would have been technically applicable but was not the ship's official prefix." },

  // ── Pop Culture – Music ──────────────────────────────────────────────────────
  { id: 'daily-106', question: 'How many Grammy Awards has Beyoncé won (as of 2024)?', answer: '32', options: ['32', '28', '25', '20'], explanation: "Beyoncé has won 32 Grammy Awards — more than any other artist in history, breaking the previous record of 31 held by classical conductor Georg Solti. Her wins span pop, R&B, country, and rap categories, reflecting a career that has continuously expanded across genres." },
  { id: 'daily-107', question: 'Which band recorded "Bohemian Rhapsody"?', answer: 'Queen', options: ['Queen', 'The Beatles', 'Led Zeppelin', 'Rolling Stones'], explanation: "Queen's 'Bohemian Rhapsody' (1975) is nearly 6 minutes long and blends ballad, opera, and hard rock in a structure unlike anything on radio at the time. Radio DJs initially refused to play it due to its length, but after DJ Kenny Everett aired it anyway, public demand was so overwhelming it became an inevitable hit." },
  { id: 'daily-108', question: 'What instrument does Elton John famously play?', answer: 'Piano', options: ['Piano', 'Guitar', 'Drums', 'Synthesizer'], explanation: "Elton John began playing piano by ear at age 3 and was accepted into the Royal Academy of Music in London at age 11. He has sold more than 300 million records worldwide and is known for his flamboyant performance style and elaborate piano arrangements that span rock, pop, and gospel influences." },
  { id: 'daily-109', question: 'Which city is known as the birthplace of jazz?', answer: 'New Orleans', options: ['New Orleans', 'Chicago', 'New York', 'Memphis'], explanation: "Jazz emerged in New Orleans in the late 19th and early 20th century from a unique blend of African rhythms, blues, ragtime, and European harmonic structures. The city's multicultural mix of African, Creole, French, and Spanish influences created the cultural conditions for this entirely new musical form." },
  { id: 'daily-110', question: 'Who is the best-selling solo music artist of all time?', answer: 'Michael Jackson', options: ['Michael Jackson', 'Elvis Presley', 'Madonna', 'The Beatles'], explanation: "Michael Jackson has sold an estimated 350–400 million records worldwide. His album Thriller (1982) remains the best-selling album of all time with over 70 million copies sold, and he pioneered the use of music videos as artistic statements through iconic films like 'Billie Jean' and 'Thriller.'" },
  { id: 'daily-111', question: 'What nationality was classical composer Ludwig van Beethoven?', answer: 'German', options: ['German', 'Austrian', 'French', 'Polish'], explanation: "Beethoven was born in Bonn, Germany in 1770, making him German — though he spent most of his adult life in Vienna, Austria, which leads many to assume he was Austrian. He composed some of his greatest works, including his Ninth Symphony, after becoming completely deaf." },
  { id: 'daily-112', question: 'Which band was Freddie Mercury the lead singer of?', answer: 'Queen', options: ['Queen', 'Aerosmith', 'Journey', 'Foreigner'], explanation: "Freddie Mercury was the lead vocalist and pianist of Queen, known for his extraordinary four-octave vocal range and electrifying stage presence. Born Farrokh Bulsara in Zanzibar to Parsi Indian parents, he died in 1991 from bronchopneumonia as a complication of AIDS, announcing his diagnosis just one day before his death." },
  { id: 'daily-113', question: 'What was Michael Jackson\'s moonwalk-debut music video?', answer: 'Billie Jean', options: ['Billie Jean', 'Thriller', 'Beat It', 'Smooth Criminal'], explanation: "Michael Jackson performed the moonwalk publicly for the first time on the 'Motown 25: Yesterday, Today and Forever' TV special in 1983 while performing 'Billie Jean.' The move — a gliding backward step that appears to defy gravity — became his signature and is often cited as one of the most iconic moments in pop music history." },
  { id: 'daily-114', question: 'Which singer is known as the "Queen of Pop"?', answer: 'Madonna', options: ['Madonna', 'Beyoncé', 'Rihanna', 'Lady Gaga'], explanation: "Madonna earned the 'Queen of Pop' title through her ability to reinvent her image and sound across five decades. She was among the first artists to use music videos as high-concept art, and her provocative performances and constant reinvention made her a template for pop stardom that artists continue to reference." },
  { id: 'daily-115', question: 'How many strings does a standard guitar have?', answer: '6', options: ['6', '4', '8', '12'], explanation: "A standard guitar has 6 strings, typically tuned E-A-D-G-B-E from lowest to highest. Bass guitars have 4 strings, 7-string guitars exist for extended range, and 12-string guitars have six pairs of strings (each pair tuned to the same or octave pitch) to produce a fuller, richer sound." },

  // ── Pop Culture – TV ─────────────────────────────────────────────────────────
  { id: 'daily-116', question: 'Which TV show features the fictional paper company Dunder Mifflin?', answer: 'The Office', options: ['The Office', 'Parks and Recreation', '30 Rock', 'Arrested Development'], explanation: "The US version of The Office ran from 2005 to 2013 and was adapted from Ricky Gervais and Stephen Merchant's British series. It initially imitated the original closely before finding its own voice in Season 2, eventually running far longer than its source and cementing Steve Carell's Michael Scott as one of television's most iconic comedic characters." },
  { id: 'daily-117', question: 'In Game of Thrones, what is the motto of House Stark?', answer: 'Winter is Coming', options: ['Winter is Coming', 'Fire and Blood', 'We Do Not Sow', 'Ours is the Fury'], explanation: "'Winter is Coming' functions as both a literal warning about Westeros's long seasonal winters and as the Stark family's philosophical outlook — a reminder to stay vigilant and prepared during periods of peace. 'Fire and Blood' belongs to House Targaryen, 'We Do Not Sow' to House Greyjoy, and 'Ours is the Fury' to House Baratheon." },
  { id: 'daily-118', question: 'Which show is set in the fictional town of Hawkins, Indiana?', answer: 'Stranger Things', options: ['Stranger Things', 'Twin Peaks', 'The OA', 'Dark'], explanation: "Stranger Things, created by the Duffer Brothers, is set in Hawkins, Indiana in the 1980s and draws heavily on the era's pop culture — particularly Spielberg films, Stephen King novels, and Dungeons & Dragons. Its heavy nostalgic appeal introduced many younger viewers to 1980s cultural touchstones they had no direct memory of." },
  { id: 'daily-119', question: 'How many seasons does Breaking Bad have?', answer: '5', options: ['5', '4', '6', '3'], explanation: "Breaking Bad ran for 5 seasons (62 episodes) from 2008 to 2013 on AMC. It started with modest ratings but grew dramatically through DVD and Netflix availability, holding a Guinness World Record as the highest-rated TV series ever based on Metacritic scores at the time of its finale." },
  { id: 'daily-120', question: 'What is the name of the coffee shop in Friends?', answer: 'Central Perk', options: ['Central Perk', 'The Coffee House', 'Perks', 'Java Joe\'s'], explanation: "Central Perk became so iconic that a real Central Perk café opened in New York City for the show's 20th anniversary in 2014. The orange couch was always magically available for the group — a running implausibility writers half-addressed with an occasional 'reserved' sign that became a self-aware joke." },
  { id: 'daily-121', question: 'Which streaming service produced Stranger Things?', answer: 'Netflix', options: ['Netflix', 'HBO', 'Amazon Prime', 'Hulu'], explanation: "Stranger Things premiered on Netflix in July 2016 and became one of the platform's most successful original series. Netflix used the show's popularity to demonstrate that streaming originals could rival traditional network television in cultural impact and production quality." },
  { id: 'daily-122', question: 'What is the longest-running animated TV show in the US?', answer: 'The Simpsons', options: ['The Simpsons', 'South Park', 'Family Guy', 'Futurama'], explanation: "The Simpsons premiered on December 17, 1989 and has aired over 760 episodes — making it the longest-running American animated series and prime-time scripted TV series. Its cultural influence is so broad that the term 'Simpsons did it first' is used when any other show's plotline turns out to have been covered by Springfield decades earlier." },
  { id: 'daily-123', question: 'In which TV show do characters say "Winter is Coming"?', answer: 'Game of Thrones', options: ['Game of Thrones', 'The Witcher', 'Vikings', 'Merlin'], explanation: "'Winter is Coming' is the motto of House Stark and one of Game of Thrones' most recognizable phrases. The show, based on George R.R. Martin's A Song of Ice and Fire novels, ran from 2011 to 2019 and became HBO's most watched series ever, though its final season was divisive among fans." },
  { id: 'daily-124', question: 'Which show features a chemistry teacher turned drug manufacturer?', answer: 'Breaking Bad', options: ['Breaking Bad', 'Ozark', 'Narcos', 'Better Call Saul'], explanation: "Breaking Bad follows Walter White, a high school chemistry teacher who turns to manufacturing methamphetamine after a lung cancer diagnosis. Creator Vince Gilligan described the show's concept as 'turning Mr. Chips into Scarface' — a gradual moral descent that became one of television's most celebrated character arcs." },
  { id: 'daily-125', question: 'What fictional kingdom is the setting for The Crown?', answer: 'United Kingdom', options: ['United Kingdom', 'Denmark', 'Sweden', 'Netherlands'], explanation: "The Crown dramatizes the reign of Queen Elizabeth II and is set in the very real United Kingdom — it is not fictional at all. The show is notable for recasting its entire ensemble every two seasons to portray the royal family at different ages, with three different actresses playing Elizabeth II across the series." },

  // ── Sports ───────────────────────────────────────────────────────────────────
  { id: 'daily-126', question: 'How many players are on a soccer team on the field?', answer: '11', options: ['11', '10', '12', '9'], explanation: "Each soccer team fields 11 players including the goalkeeper. If a player is sent off with a red card and no substitutes remain, the team must play with fewer players; teams can use up to 3–5 substitutes depending on competition rules." },
  { id: 'daily-127', question: 'Which country has won the most FIFA World Cups?', answer: 'Brazil', options: ['Brazil', 'Germany', 'Italy', 'Argentina'], explanation: "Brazil has won the FIFA World Cup five times (1958, 1962, 1970, 1994, 2002) — more than any other nation. They are the only country to have qualified for every World Cup since the tournament began in 1930, and the 1970 team featuring Pelé is widely considered the greatest international squad ever assembled." },
  { id: 'daily-128', question: 'In which sport would you perform a slam dunk?', answer: 'Basketball', options: ['Basketball', 'Volleyball', 'Handball', 'Water polo'], explanation: "A slam dunk in basketball involves jumping and pushing the ball directly downward through the hoop — a high-percentage shot that also energizes crowds. The move became popularized in the NBA by players like Julius Erving (Dr. J) and Michael Jordan, whose dunks were so spectacular they helped launch the sport into mainstream global popularity." },
  { id: 'daily-129', question: 'Who holds the record for most Olympic gold medals?', answer: 'Michael Phelps', options: ['Michael Phelps', 'Usain Bolt', 'Carl Lewis', 'Mark Spitz'], explanation: "Michael Phelps won 23 Olympic gold medals (28 total medals) across four Games from 2000 to 2016 — more than any athlete in Olympic history. He won 8 golds at a single Games (Beijing 2008), breaking Mark Spitz's record of 7 from 1972 and cementing his status as the greatest Olympic swimmer of all time." },
  { id: 'daily-130', question: 'How long is a marathon in kilometers?', answer: '42.195 km', options: ['42.195 km', '40 km', '45 km', '50 km'], explanation: "The marathon distance of 42.195 km (26 miles, 385 yards) was standardized at the 1908 London Olympics. The extra 385 yards were added so the race would finish in front of the Royal Box at the stadium — a quirk that became the official distance for all future marathons." },
  { id: 'daily-131', question: 'Which country invented the sport of cricket?', answer: 'England', options: ['England', 'India', 'Australia', 'South Africa'], explanation: "Cricket originated in England, with the earliest definite references dating to 16th-century southeastern England. It was spread to many countries through the British Empire, which is why the sport is most popular in former British colonies — India, Australia, Pakistan, the Caribbean, and South Africa." },
  { id: 'daily-132', question: 'In tennis, what is the term for a score of 40-40?', answer: 'Deuce', options: ['Deuce', 'Advantage', 'Break point', 'Tie'], explanation: "In tennis, 40-40 is called 'deuce,' from the French 'à deux le jeu' (two points to win the game). From deuce, a player must win two consecutive points to take the game — the first is called 'advantage,' and if they win the next point, they take the game; if not, the score returns to deuce." },
  { id: 'daily-133', question: 'How many holes are in a standard round of golf?', answer: '18', options: ['18', '9', '12', '24'], explanation: "A standard round of golf consists of 18 holes, a convention standardized by the Royal and Ancient Golf Club of St Andrews in 1858. The number 18 famously matches the shots in a bottle of whisky — leading to the apocryphal story that golfers play 18 holes because that's when the whisky runs out, though the actual origin is simply that St Andrews' famous course had 18 holes." },
  { id: 'daily-134', question: 'Which athlete is known as "The Greatest" in boxing?', answer: 'Muhammad Ali', options: ['Muhammad Ali', 'Mike Tyson', 'Joe Frazier', 'George Foreman'], explanation: "Muhammad Ali proclaimed himself 'The Greatest' and backed it up with three world heavyweight championship reigns and victories over Joe Frazier and George Foreman. Beyond boxing, he was equally significant as a civil rights figure — his refusal to be drafted into the Vietnam War, citing his religious beliefs, cost him the prime years of his career." },
  { id: 'daily-135', question: 'What sport is played at Wimbledon?', answer: 'Tennis', options: ['Tennis', 'Cricket', 'Croquet', 'Polo'], explanation: "Wimbledon is the oldest tennis Grand Slam tournament, first held in 1877 at the All England Lawn Tennis and Croquet Club in London. It is the only Grand Slam still played on grass courts and is famous for its strict all-white dress code for players, a tradition dating back to the Victorian era." },
  { id: 'daily-136', question: 'Which country hosted the 2016 Summer Olympics?', answer: 'Brazil', options: ['Brazil', 'Argentina', 'Japan', 'China'], explanation: "Brazil hosted the 2016 Summer Olympics in Rio de Janeiro — the first Olympic Games held in South America. The Games were notable for Usain Bolt completing the 'triple triple' (100m, 200m, and 4×100m relay gold at three consecutive Olympics) and for Michael Phelps' farewell that cemented his Olympic legacy." },
  { id: 'daily-137', question: 'In which sport do players use a puck?', answer: 'Ice hockey', options: ['Ice hockey', 'Field hockey', 'Lacrosse', 'Polo'], explanation: "Ice hockey uses a hard rubber puck approximately 25mm thick and 76mm in diameter. A puck shot by a professional player can travel over 160 km/h (100 mph); the black rubber disc replaced an earlier ball, which moved too unpredictably on ice surfaces." },
  { id: 'daily-138', question: 'How many Grand Slam titles did Serena Williams win?', answer: '23', options: ['23', '20', '18', '25'], explanation: "Serena Williams won 23 Grand Slam singles titles — the most by any player in the Open Era and the most by any woman in history. Her Australian Open 2017 title was won while she was 8 weeks pregnant, arguably her most remarkable victory; she retired from professional tennis in 2022." },
  { id: 'daily-139', question: 'What is the national sport of Japan?', answer: 'Sumo wrestling', options: ['Sumo wrestling', 'Judo', 'Karate', 'Baseball'], explanation: "Sumo wrestling is Japan's national sport and has roots going back over 1,500 years, deeply intertwined with Shinto religious rituals. Despite baseball being more popular in terms of viewership and participation, sumo holds its special cultural status; wrestlers (rikishi) are among Japan's most celebrated athletes." },
  { id: 'daily-140', question: 'Which city hosted the first modern Olympic Games?', answer: 'Athens', options: ['Athens', 'Paris', 'London', 'Stockholm'], explanation: "Athens hosted the first modern Olympic Games in 1896, with 241 athletes from 14 nations competing in 43 events. The Games were revived by French educator Pierre de Coubertin, inspired by ancient Greek Olympic Games that had been held from 776 BC until 393 AD." },

  // ── Food & Drink ─────────────────────────────────────────────────────────────
  { id: 'daily-141', question: 'Which country is the world\'s largest producer of coffee?', answer: 'Brazil', options: ['Brazil', 'Colombia', 'Ethiopia', 'Vietnam'], explanation: "Brazil has been the world's largest coffee producer for over 150 years, producing about a third of the world's supply. Coffee is believed to have originated in Ethiopia (where the Kaffa region may have given coffee its name), but Brazil's tropical climate and vast agricultural land made it the dominant global producer." },
  { id: 'daily-142', question: 'What is the main ingredient in guacamole?', answer: 'Avocado', options: ['Avocado', 'Tomato', 'Lime', 'Onion'], explanation: "Guacamole is made primarily from mashed avocados, with the word itself coming from the Nahuatl 'āhuacamōlli' — a combination of āhuacatl (avocado) and mōlli (sauce). The dish originated with the Aztecs in pre-colonial Mexico, where avocados were considered a luxury food." },
  { id: 'daily-143', question: 'Which country invented sushi?', answer: 'Japan', options: ['Japan', 'China', 'Korea', 'Thailand'], explanation: "Sushi as we know it evolved in Japan, but its origins trace to Southeast Asia — a preservation technique of fermenting fish with rice. Modern sushi (with fresh fish and vinegared rice eaten fresh) was developed in Tokyo (then Edo) in the early 19th century by chef Hanaya Yohei as a fast street food." },
  { id: 'daily-144', question: 'What nut is used to make marzipan?', answer: 'Almond', options: ['Almond', 'Walnut', 'Cashew', 'Pistachio'], explanation: "Marzipan is made from ground almonds, sugar, and sometimes egg whites — a confection popular across Europe and the Middle East. Lübeck, Germany and Toledo, Spain both claim to have invented marzipan; the city of Lübeck is so proud of its version that 'Lübecker Marzipan' has protected geographical status in the EU." },
  { id: 'daily-145', question: 'Which spice is the most expensive in the world by weight?', answer: 'Saffron', options: ['Saffron', 'Vanilla', 'Cardamom', 'Turmeric'], explanation: "Saffron can cost over $5,000 per kilogram because each flower of the Crocus sativus plant produces only three stigmas, which must be hand-harvested. It takes around 75,000 flowers to produce just one pound of saffron; Iran produces about 90% of the world's supply." },
  { id: 'daily-146', question: 'What is the national dish of Spain?', answer: 'Paella', options: ['Paella', 'Tapas', 'Gazpacho', 'Tortilla española'], explanation: "Paella originated in Valencia, Spain, traditionally made with rice, saffron, vegetables, and either seafood or meat — but not both (mixing seafood and meat is considered a tourist adaptation). The word 'paella' refers to the wide, shallow pan in which it is cooked." },
  { id: 'daily-147', question: 'Which fruit is known as the "king of fruits" in Southeast Asia?', answer: 'Durian', options: ['Durian', 'Mango', 'Jackfruit', 'Papaya'], explanation: "Durian is called the 'king of fruits' across Southeast Asia for its rich, custard-like flesh — but it is also notorious for its extraordinarily pungent smell, which has been described as everything from ripe cheese to sewage. It is banned in many hotels, public transport systems, and airports across the region." },
  { id: 'daily-148', question: 'What type of pasta is shaped like small rice grains?', answer: 'Orzo', options: ['Orzo', 'Risoni', 'Farfalle', 'Stelline'], explanation: "Orzo (Italian for 'barley') is a pasta shaped like large rice grains; 'risoni' is essentially the same shape under a different name. Unlike actual rice, orzo is made from wheat flour and behaves like pasta when cooked, making it versatile in soups, salads, and as a rice substitute." },
  { id: 'daily-149', question: 'Which country is the origin of the croissant?', answer: 'Austria', options: ['Austria', 'France', 'Germany', 'Switzerland'], explanation: "The croissant originated in Austria as the 'kipferl,' a crescent-shaped pastry that dates back centuries. It was brought to France in the 1830s, where Viennese baker August Zang opened a bakery in Paris and the French adapted it using laminated dough — the flaky, buttery technique that defines the modern croissant." },
  { id: 'daily-150', question: 'What gives red wine its colour?', answer: 'Grape skins', options: ['Grape skins', 'Grape seeds', 'Fermentation process', 'Added colorant'], explanation: "Red wine gets its colour from anthocyanin pigments found in the grape skins, which leach into the juice during fermentation when the skins are left in contact with the juice. White wine is made with minimal skin contact (or white grapes), and rosé sits somewhere in between with limited skin contact time." },

  // ── Language & Literature ────────────────────────────────────────────────────
  { id: 'daily-151', question: 'Who wrote Romeo and Juliet?', answer: 'William Shakespeare', options: ['William Shakespeare', 'Christopher Marlowe', 'John Milton', 'Geoffrey Chaucer'], explanation: "Romeo and Juliet was written by Shakespeare around 1594–1596 and is based on an Italian tale retold in a 1562 English poem. It introduced the phrase 'star-crossed lovers' into the English language and remains the most performed of all Shakespeare's plays worldwide." },
  { id: 'daily-152', question: 'What is the most spoken language in the world by native speakers?', answer: 'Mandarin Chinese', options: ['Mandarin Chinese', 'English', 'Spanish', 'Hindi'], explanation: "Mandarin Chinese has roughly 920 million native speakers, making it the most spoken first language in the world. English has far more total speakers when second-language speakers are counted, but Mandarin leads comfortably by native speaker count — reflecting China's enormous population." },
  { id: 'daily-153', question: 'Who wrote 1984?', answer: 'George Orwell', options: ['George Orwell', 'Aldous Huxley', 'Ray Bradbury', 'H.G. Wells'], explanation: "George Orwell wrote 1984 in 1948 while seriously ill with tuberculosis on the remote Scottish island of Jura. The novel's surveillance concepts — Big Brother, the Thought Police, doublethink, and Newspeak — have become shorthand for authoritarian overreach and entered everyday English as political vocabulary." },
  { id: 'daily-154', question: 'How many letters are in the English alphabet?', answer: '26', options: ['26', '24', '28', '25'], explanation: "The modern English alphabet has 26 letters and descended from the Latin alphabet. The Latin alphabet itself had only 23 letters — J, U, and W were added later; J and U were originally just alternate forms of I and V, and W was literally a 'double U' added for sounds Latin lacked." },
  { id: 'daily-155', question: 'Who wrote Pride and Prejudice?', answer: 'Jane Austen', options: ['Jane Austen', 'Charlotte Brontë', 'Emily Brontë', 'George Eliot'], explanation: "Jane Austen wrote Pride and Prejudice in 1813, though an early version called 'First Impressions' was completed in 1797. The novel's opening line — 'It is a truth universally acknowledged, that a single man in possession of a good fortune, must be in want of a wife' — is one of the most famous in English literature." },
  { id: 'daily-156', question: 'In which language was the New Testament originally written?', answer: 'Greek', options: ['Greek', 'Latin', 'Aramaic', 'Hebrew'], explanation: "The New Testament was written in Koine Greek — the common dialect spoken across the eastern Mediterranean during the Roman Empire. Jesus and his disciples likely spoke Aramaic in daily life, but Greek was chosen for the written texts because it was the lingua franca of the educated world at the time." },
  { id: 'daily-157', question: 'Who wrote the Harry Potter series?', answer: 'J.K. Rowling', options: ['J.K. Rowling', 'J.R.R. Tolkien', 'C.S. Lewis', 'Philip Pullman'], explanation: "J.K. Rowling conceived Harry Potter on a delayed train from Manchester to London in 1990 and wrote the first book while a single mother on welfare in Edinburgh cafes. The series has sold over 500 million copies worldwide and has been translated into 85 languages — the most translated book series in history." },
  { id: 'daily-158', question: 'What is the longest word in the English language?', answer: 'Pneumonoultramicroscopicsilicovolcanoconiosis', options: ['Pneumonoultramicroscopicsilicovolcanoconiosis', 'Supercalifragilisticexpialidocious', 'Antidisestablishmentarianism', 'Floccinaucinihilipilification'], explanation: "Pneumonoultramicroscopicsilicovolcanoconiosis (45 letters) refers to a lung disease caused by inhaling fine silica dust from volcanoes. It was coined in 1935 by the president of the National Puzzlers' League specifically to create the longest word in English — making it more of a linguistic stunt than a medical term actually used by doctors." },
  { id: 'daily-159', question: 'Who wrote The Great Gatsby?', answer: 'F. Scott Fitzgerald', options: ['F. Scott Fitzgerald', 'Ernest Hemingway', 'John Steinbeck', 'William Faulkner'], explanation: "F. Scott Fitzgerald published The Great Gatsby in 1925 to modest sales and mixed reviews — he died in 1940 believing it a failure. The novel was distributed to American soldiers in World War II, which revived interest in it; it is now one of the best-selling novels in history and a staple of American high school curricula." },
  { id: 'daily-160', question: 'Which ancient language is considered the ancestor of most European languages?', answer: 'Proto-Indo-European', options: ['Proto-Indo-European', 'Latin', 'Sanskrit', 'Ancient Greek'], explanation: "Proto-Indo-European (PIE) is the reconstructed common ancestor of the Indo-European language family, which includes English, Spanish, French, German, Russian, Hindi, and Persian. It was spoken roughly 4,500–6,000 years ago and has never been directly recorded — linguists reconstructed it by comparing patterns across its descendant languages." },
  { id: 'daily-161', question: 'How many plays did Shakespeare write?', answer: '37', options: ['37', '30', '42', '25'], explanation: "Shakespeare is credited with 37 plays, though scholars debate whether a 38th (The Two Noble Kinsmen, co-written with John Fletcher) should be added to the canon. He also wrote 154 sonnets and several longer poems; remarkably, none of his original manuscripts survive — all texts derive from later printed editions." },
  { id: 'daily-162', question: 'Who wrote The Odyssey?', answer: 'Homer', options: ['Homer', 'Virgil', 'Sophocles', 'Plato'], explanation: "The Odyssey is attributed to Homer, a Greek poet believed to have lived in the 8th century BC. Whether Homer was a single historical person or a tradition of oral poets is debated — the 'Homeric Question' — but the Odyssey and the Iliad together form the foundation of the Western literary canon." },
  { id: 'daily-163', question: 'What does "et cetera" mean in Latin?', answer: 'And the rest', options: ['And the rest', 'For example', 'That is', 'Among other things'], explanation: "'Et cetera' (abbreviated etc.) literally means 'and the rest' or 'and other things' in Latin. Common Latin abbreviations in English often cause confusion: 'e.g.' (exempli gratia) means 'for example,' while 'i.e.' (id est) means 'that is' — both are frequently mixed up even by native English writers." },
  { id: 'daily-164', question: 'Who wrote Crime and Punishment?', answer: 'Fyodor Dostoevsky', options: ['Fyodor Dostoevsky', 'Leo Tolstoy', 'Anton Chekhov', 'Ivan Turgenev'], explanation: "Dostoevsky published Crime and Punishment in 1866, exploring the psychology of a student who murders a pawnbroker and then unravels under guilt. Dostoevsky wrote it under financial pressure, dictating part of the manuscript to meet a deadline — the stenographer he hired, Anna Snitkina, later became his wife." },
  { id: 'daily-165', question: 'Which punctuation mark is used to indicate a question?', answer: 'Question mark', options: ['Question mark', 'Exclamation mark', 'Semicolon', 'Colon'], explanation: "The question mark evolved from the Latin word 'quaestio' (question), which medieval scribes abbreviated as 'qo' — the q gradually curled over the o to form the modern symbol. Not all languages use the same mark; Spanish uses an inverted question mark (¿) at the start of questions as well as a standard one at the end." },

  // ── Technology ───────────────────────────────────────────────────────────────
  { id: 'daily-166', question: 'Who co-founded Apple with Steve Jobs?', answer: 'Steve Wozniak', options: ['Steve Wozniak', 'Bill Gates', 'Paul Allen', 'Tim Cook'], explanation: "Steve Wozniak (Woz) designed the Apple I and Apple II computers almost entirely on his own — Jobs was the visionary salesman and product designer who recognised their commercial potential. Apple was actually co-founded by three people: Jobs, Wozniak, and Ronald Wayne, who sold his 10% stake for $800 and famously missed out on billions." },
  { id: 'daily-167', question: 'In what year was the World Wide Web invented?', answer: '1989', options: ['1989', '1991', '1985', '1993'], explanation: "Tim Berners-Lee proposed the World Wide Web in 1989 while working at CERN in Switzerland, publishing the first website in 1991. The Web and the Internet are often confused — the Internet is the global network of computers, while the Web is one system (using HTTP and HTML) that runs on top of it." },
  { id: 'daily-168', question: 'What does CPU stand for?', answer: 'Central Processing Unit', options: ['Central Processing Unit', 'Computer Processing Unit', 'Core Processing Unit', 'Central Program Unit'], explanation: "The CPU is the primary component that executes instructions in a computer, performing arithmetic, logic, and control operations. Modern CPUs contain multiple cores allowing parallel processing; a GPU (Graphics Processing Unit) handles graphics calculations and, increasingly, AI workloads due to its massively parallel architecture." },
  { id: 'daily-169', question: 'Which company created the Android operating system?', answer: 'Google', options: ['Google', 'Samsung', 'Apple', 'Microsoft'], explanation: "Android was originally developed by Android Inc., a small startup that Google acquired in 2005 for $50 million. Google then open-sourced the OS under the Android Open Source Project, allowing any manufacturer to use it — which is why Android now powers around 72% of all smartphones globally." },
  { id: 'daily-170', question: 'What does HTML stand for?', answer: 'HyperText Markup Language', options: ['HyperText Markup Language', 'High Text Machine Language', 'HyperText Modern Language', 'Hybrid Text Markup Language'], explanation: "HTML is the standard language for structuring web pages, defining elements like headings, paragraphs, links, and images. The 'HyperText' part refers to hyperlinks that connect documents — the core concept Tim Berners-Lee built the web around, allowing non-linear navigation between pages." },
  { id: 'daily-171', question: 'Who founded Microsoft?', answer: 'Bill Gates and Paul Allen', options: ['Bill Gates and Paul Allen', 'Steve Jobs and Steve Wozniak', 'Larry Page and Sergey Brin', 'Mark Zuckerberg and Eduardo Saverin'], explanation: "Bill Gates and Paul Allen founded Microsoft in 1975 after dropping out of Harvard and moving to Albuquerque, New Mexico to develop software for the Altair 8800 microcomputer. Their early decision to license rather than sell their DOS operating system to IBM — retaining the right to sell it to others — became the foundation of Microsoft's dominance." },
  { id: 'daily-172', question: 'What was the first commercially successful video game?', answer: 'Pong', options: ['Pong', 'Space Invaders', 'Pac-Man', 'Tetris'], explanation: "Pong, released by Atari in 1972, was a simple table tennis simulation that became the first commercially successful arcade video game. The very first video game is generally considered to be Tennis for Two (1958) or Spacewar! (1962), but neither achieved commercial distribution — Pong was the game that launched the industry." },
  { id: 'daily-173', question: 'Which programming language was created by Guido van Rossum?', answer: 'Python', options: ['Python', 'Java', 'Ruby', 'Perl'], explanation: "Guido van Rossum created Python in 1991, naming it after Monty Python's Flying Circus rather than the snake. He served as Python's 'Benevolent Dictator For Life' (BDFL) until stepping down in 2018; Python is now one of the world's most popular languages, dominating data science, AI, and web development." },
  { id: 'daily-174', question: 'What does GPS stand for?', answer: 'Global Positioning System', options: ['Global Positioning System', 'General Positioning Satellite', 'Global Precision System', 'Geo-Positioning System'], explanation: "GPS is operated by the US military and uses a constellation of at least 24 satellites to provide location data anywhere on Earth. GPS must account for Einstein's theory of relativity to maintain accuracy — the satellites' clocks run slightly faster due to weaker gravity at altitude, requiring constant relativistic corrections or navigation errors would accumulate by kilometres per day." },
  { id: 'daily-175', question: 'Which company makes the iPhone?', answer: 'Apple', options: ['Apple', 'Samsung', 'Google', 'Sony'], explanation: "Apple introduced the iPhone on January 9, 2007, when Steve Jobs described it as 'an iPod, a phone, and an internet communicator' combined. It transformed the mobile industry and established the app ecosystem business model — the App Store, launched in 2008, now generates over $100 billion annually." },
  { id: 'daily-176', question: 'What year was Facebook founded?', answer: '2004', options: ['2004', '2003', '2005', '2006'], explanation: "Mark Zuckerberg launched 'TheFacebook' in February 2004 from his Harvard dorm room, initially restricting it to Harvard students. The 'The' was dropped in 2005, and the platform expanded to the public in 2006; the company was rebranded as Meta in 2021 to reflect Zuckerberg's pivot toward building the 'metaverse.'" },
  { id: 'daily-177', question: 'What does USB stand for?', answer: 'Universal Serial Bus', options: ['Universal Serial Bus', 'Unified System Bridge', 'Universal Storage Bus', 'Unlimited Serial Board'], explanation: "USB was developed in the mid-1990s by a group of companies including Intel, IBM, and Microsoft to standardise how peripherals connect to computers. Before USB, devices used a bewildering range of connectors (serial ports, parallel ports, PS/2, etc.); USB's plug-and-play design replaced most of them with one universal standard." },
  { id: 'daily-178', question: 'Who invented the telephone?', answer: 'Alexander Graham Bell', options: ['Alexander Graham Bell', 'Thomas Edison', 'Nikola Tesla', 'Guglielmo Marconi'], explanation: "Alexander Graham Bell is credited with patenting the telephone in 1876, though Elisha Gray filed a competing patent application on the same day — Bell's was processed first by hours. Italian inventor Antonio Meucci had also developed a voice communication device years earlier and filed a notice of intent, but lacked the money to complete the patent." },
  { id: 'daily-179', question: 'What is the name of Elon Musk\'s space company?', answer: 'SpaceX', options: ['SpaceX', 'Blue Origin', 'Virgin Galactic', 'Rocket Lab'], explanation: "SpaceX (Space Exploration Technologies Corp.) was founded by Elon Musk in 2002 with the goal of making humanity multi-planetary. It became the first private company to send astronauts to the International Space Station and pioneered reusable rocket boosters — dramatically reducing the cost of reaching orbit." },
  { id: 'daily-180', question: 'Which language runs in a web browser natively?', answer: 'JavaScript', options: ['JavaScript', 'Python', 'Ruby', 'PHP'], explanation: "JavaScript is the only programming language that runs natively in web browsers, making it the universal language of interactive web pages. Despite sharing a name, it has almost no relation to Java — the name was a marketing decision in 1995 to piggyback on Java's popularity, creating decades of confusion." },

  // ── Art & Architecture ───────────────────────────────────────────────────────
  { id: 'daily-181', question: 'Who painted the Mona Lisa?', answer: 'Leonardo da Vinci', options: ['Leonardo da Vinci', 'Michelangelo', 'Raphael', 'Botticelli'], explanation: "Leonardo da Vinci painted the Mona Lisa between approximately 1503 and 1519, and it is believed to depict Lisa Gherardini, wife of a Florentine merchant. It was famously stolen from the Louvre in 1911 and recovered two years later — the theft made it a global sensation and is partly responsible for its status as the world's most famous painting." },
  { id: 'daily-182', question: 'In which museum is the Mona Lisa displayed?', answer: 'The Louvre', options: ['The Louvre', 'The Uffizi', 'The Prado', 'The Met'], explanation: "The Mona Lisa hangs in the Louvre Museum in Paris, which is the world's most visited art museum. Despite its fame, visitors are often surprised by how small the painting is — just 77 × 53 cm — and how far back it sits behind bullet-proof glass, making it difficult to appreciate in person." },
  { id: 'daily-183', question: 'Who sculpted David?', answer: 'Michelangelo', options: ['Michelangelo', 'Donatello', 'Bernini', 'Rodin'], explanation: "Michelangelo carved David from a single block of marble between 1501 and 1504, when he was in his mid-twenties. The block had previously been worked on and abandoned by two other sculptors; at over 5 metres tall, the finished statue depicts the biblical hero just before his battle with Goliath and is now displayed in Florence's Galleria dell'Accademia." },
  { id: 'daily-184', question: 'Which architect designed the Sydney Opera House?', answer: 'Jørn Utzon', options: ['Jørn Utzon', 'Frank Lloyd Wright', 'Renzo Piano', 'Zaha Hadid'], explanation: "Danish architect Jørn Utzon won the international design competition for the Sydney Opera House in 1957 but resigned in 1966 due to disputes with the New South Wales government and never saw the completed building. It opened in 1973 and became a UNESCO World Heritage Site in 2007 — the fastest any building has received that status." },
  { id: 'daily-185', question: 'Who painted The Starry Night?', answer: 'Vincent van Gogh', options: ['Vincent van Gogh', 'Paul Gauguin', 'Claude Monet', 'Paul Cézanne'], explanation: "Van Gogh painted The Starry Night in June 1889 while voluntarily staying at an asylum in Saint-Rémy-de-Provence, France, depicting the view from his window. He sold only one painting during his lifetime and died at 37, but his work now sells for hundreds of millions; The Starry Night is held by the Museum of Modern Art in New York." },
  { id: 'daily-186', question: 'Which art movement is Salvador Dalí associated with?', answer: 'Surrealism', options: ['Surrealism', 'Cubism', 'Dadaism', 'Expressionism'], explanation: "Salvador Dalí was a leading figure in Surrealism, a movement that sought to unlock the unconscious mind by depicting dreamlike, irrational imagery. He was eventually expelled from the official Surrealist group by André Breton, who accused him of political opportunism — Dalí responded by anagramming Breton's name into 'Avida Dollars.'" },
  { id: 'daily-187', question: 'Who painted the Sistine Chapel ceiling?', answer: 'Michelangelo', options: ['Michelangelo', 'Leonardo da Vinci', 'Raphael', 'Botticelli'], explanation: "Michelangelo painted the Sistine Chapel ceiling between 1508 and 1512, covering nearly 500 square metres with scenes from Genesis. He painted it standing up rather than lying on his back (as commonly depicted) — he designed a curved scaffold to work from. The 'Creation of Adam' scene, with God reaching toward Adam, is the most replicated image in Western art." },
  { id: 'daily-188', question: 'Which architectural style features pointed arches and flying buttresses?', answer: 'Gothic', options: ['Gothic', 'Baroque', 'Romanesque', 'Renaissance'], explanation: "Gothic architecture emerged in 12th-century France and used pointed arches, ribbed vaults, and flying buttresses to allow thinner walls and larger windows filled with stained glass. Notre-Dame de Paris and Chartres Cathedral are classic examples; the style allowed light-filled interiors that earlier Romanesque churches with thick, heavy walls could not achieve." },
  { id: 'daily-189', question: 'Who painted The Persistence of Memory featuring melting clocks?', answer: 'Salvador Dalí', options: ['Salvador Dalí', 'René Magritte', 'Joan Miró', 'Max Ernst'], explanation: "Dalí painted The Persistence of Memory in 1931 — a small canvas (24 × 33 cm) that took him just a few hours after being inspired by a piece of melting Camembert cheese. He described the soft watches as a critique of the rigid, fixed nature of time; the painting is now one of the most recognisable works in the Museum of Modern Art's collection." },
  { id: 'daily-190', question: 'In which country is the Sagrada Família located?', answer: 'Spain', options: ['Spain', 'Portugal', 'Italy', 'France'], explanation: "The Sagrada Família basilica in Barcelona, Spain was designed by Antoni Gaudí, who devoted the last 43 years of his life to it. Construction began in 1882 and is still ongoing — Gaudí died in 1926 after being struck by a tram. It is expected to be completed around 2026, 144 years after construction began." },

  // ── Geography continued ──────────────────────────────────────────────────────
  { id: 'daily-191', question: 'What is the capital of Turkey?', answer: 'Ankara', options: ['Ankara', 'Istanbul', 'Izmir', 'Bursa'], explanation: "Ankara replaced Istanbul as Turkey's capital in 1923 when Mustafa Kemal Atatürk established the Republic of Turkey. Istanbul is by far the larger city — one of Europe's biggest — and was the capital of both the Byzantine and Ottoman Empires, which leads many people to assume it is still the capital." },
  { id: 'daily-192', question: 'Which country has the largest population in the world?', answer: 'India', options: ['India', 'China', 'USA', 'Indonesia'], explanation: "India surpassed China as the world's most populous country in 2023, reaching approximately 1.43 billion people. China's population has begun to decline due to decades of its one-child policy, while India's younger demographic means it is expected to remain the most populous nation for decades." },
  { id: 'daily-193', question: 'What is the name of the sea between Italy and the Balkans?', answer: 'Adriatic Sea', options: ['Adriatic Sea', 'Aegean Sea', 'Ionian Sea', 'Tyrrhenian Sea'], explanation: "The Adriatic Sea separates the Italian Peninsula from the Balkans (Slovenia, Croatia, Bosnia, Montenegro, and Albania). The Aegean Sea lies between Greece and Turkey to the east, while the Ionian Sea sits to the south of the Adriatic — all three are arms of the Mediterranean." },
  { id: 'daily-194', question: 'Which country is the Eiffel Tower located in?', answer: 'France', options: ['France', 'Belgium', 'Italy', 'Switzerland'], explanation: "The Eiffel Tower stands in Paris, France, and was built as a temporary entrance arch for the 1889 World's Fair. It was designed by Gustave Eiffel's company and was almost torn down in 1909 before its value as a radio transmission tower saved it — today it is the most visited monument in the world." },
  { id: 'daily-195', question: 'What is the capital of Egypt?', answer: 'Cairo', options: ['Cairo', 'Alexandria', 'Luxor', 'Giza'], explanation: "Cairo is Africa's largest city and one of the world's most densely populated, home to over 20 million people in its metropolitan area. Egypt is constructing a new administrative capital east of Cairo — currently called the 'New Administrative Capital' — to relieve congestion, though Cairo remains the cultural and economic heart of the country." },
  { id: 'daily-196', question: 'Which two countries share the longest land border?', answer: 'USA and Canada', options: ['USA and Canada', 'Russia and China', 'Brazil and Bolivia', 'India and China'], explanation: "The US-Canada border stretches 8,891 kilometres — the longest international border in the world shared by two countries. It is also the world's longest undefended border, though 'undefended' is increasingly a legal distinction rather than a physical one, with extensive surveillance systems in place." },
  { id: 'daily-197', question: 'What is the smallest ocean in the world?', answer: 'Arctic Ocean', options: ['Arctic Ocean', 'Indian Ocean', 'Southern Ocean', 'Atlantic Ocean'], explanation: "The Arctic Ocean covers approximately 14.06 million square kilometres — the smallest and shallowest of the world's five oceans. Much of it is covered by sea ice year-round, though climate change has dramatically reduced Arctic sea ice extent, opening new shipping routes and raising geopolitical competition for the region's resources." },
  { id: 'daily-198', question: 'Which river runs through London?', answer: 'Thames', options: ['Thames', 'Severn', 'Avon', 'Trent'], explanation: "The River Thames flows 346 kilometres through southern England, passing through London on its way to the North Sea. It was once so polluted it was declared 'biologically dead' in the 1950s; after major cleanup efforts the Thames now supports over 115 species of fish — one of the greatest urban river revivals in history." },
  { id: 'daily-199', question: 'What is the capital of Japan?', answer: 'Tokyo', options: ['Tokyo', 'Osaka', 'Kyoto', 'Hiroshima'], explanation: "Tokyo is the world's most populous metropolitan area, home to around 37–38 million people. It became Japan's capital in 1869 when Emperor Meiji moved the imperial seat there from Kyoto (which had been the capital for over 1,000 years); Tokyo means 'Eastern Capital,' while Kyoto means 'Capital City.'" },
  { id: 'daily-200', question: 'Which African country has the largest area?', answer: 'Algeria', options: ['Algeria', 'Sudan', 'Libya', 'Democratic Republic of Congo'], explanation: "Algeria is the largest country in Africa by area at about 2.38 million square kilometres, having taken that title from Sudan when South Sudan became independent in 2011. About 90% of Algeria's territory is covered by the Sahara Desert, making it one of the world's largest countries by area but with a population concentrated in a narrow northern strip." },

  // ── History continued ────────────────────────────────────────────────────────
  { id: 'daily-201', question: 'Who was the last Tsar of Russia?', answer: 'Nicholas II', options: ['Nicholas II', 'Alexander III', 'Peter the Great', 'Ivan the Terrible'], explanation: "Nicholas II abdicated in March 1917 during the Russian Revolution and was executed along with his entire family by Bolshevik forces in July 1918. His reluctance to reform, his reliance on the mystic Rasputin, and Russia's catastrophic losses in World War I all contributed to the fall of the 300-year Romanov dynasty." },
  { id: 'daily-202', question: 'In which year was the Eiffel Tower built?', answer: '1889', options: ['1889', '1875', '1900', '1910'], explanation: "The Eiffel Tower was completed in 1889 for the World's Fair celebrating the centennial of the French Revolution. At 300 metres it was the world's tallest man-made structure for 41 years until the Chrysler Building was completed in New York in 1930; with its broadcasting antenna it now stands 330 metres tall." },
  { id: 'daily-203', question: 'Which explorer first reached India by sailing around Africa?', answer: 'Vasco da Gama', options: ['Vasco da Gama', 'Ferdinand Magellan', 'Bartolomeu Dias', 'Christopher Columbus'], explanation: "Vasco da Gama reached Calicut (now Kozhikode) on India's southwestern coast in 1498, completing the first direct sea route from Europe to Asia. Bartolomeu Dias had rounded the Cape of Good Hope in 1488 but turned back; da Gama continued the journey and opened the spice trade route that made Portugal enormously wealthy." },
  { id: 'daily-204', question: 'What was the name of the first successful powered airplane?', answer: 'Flyer', options: ['Flyer', 'Spirit of St. Louis', 'Kitty Hawk', 'Eagle'], explanation: "The Wright brothers' aircraft was called the Flyer (sometimes Flyer I or Kitty Hawk Flyer). On December 17, 1903, Orville Wright piloted the first controlled, powered, sustained flight lasting 12 seconds at Kitty Hawk, North Carolina — Kitty Hawk was the location, not the aircraft's name. The Spirit of St. Louis was Charles Lindbergh's 1927 transatlantic plane." },
  { id: 'daily-205', question: 'In which decade did the Great Depression begin?', answer: '1920s', options: ['1920s', '1930s', '1910s', '1940s'], explanation: "The Great Depression began with the Wall Street Crash of October 1929 — often called 'Black Tuesday' — technically in the 1920s. Most people associate it with the 1930s because that is when its devastating effects on unemployment, poverty, and global trade were most severe, lasting until World War II production revived economies." },
  { id: 'daily-206', question: 'Who was the longest-reigning British monarch?', answer: 'Queen Elizabeth II', options: ['Queen Elizabeth II', 'Queen Victoria', 'King George III', 'King Henry VIII'], explanation: "Queen Elizabeth II reigned for 70 years and 214 days (1952–2022), surpassing Queen Victoria's 63-year reign in 2015. She became queen at age 25 after her father George VI died unexpectedly young; at her death in September 2022, she was 96 and the oldest reigning British monarch in history." },
  { id: 'daily-207', question: 'Which battle ended Napoleon\'s rule?', answer: 'Battle of Waterloo', options: ['Battle of Waterloo', 'Battle of Trafalgar', 'Battle of Leipzig', 'Battle of Austerlitz'], explanation: "Napoleon was decisively defeated at the Battle of Waterloo in present-day Belgium on June 18, 1815, by a coalition of British, Dutch, and Prussian forces led by the Duke of Wellington. He was exiled to Saint Helena in the South Atlantic, where he died in 1821 — 'meeting one's Waterloo' still means suffering a final, decisive defeat." },
  { id: 'daily-208', question: 'In which year was the Eiffel Tower built?', answer: '1889', options: ['1889', '1880', '1895', '1870'], explanation: "The Eiffel Tower was built for the 1889 Universal Exposition in Paris and took just over two years to construct with 300 workers. It was controversial at the time — hundreds of prominent French artists and intellectuals signed a petition calling it an eyesore — but became beloved and is now the most visited paid monument in the world." },
  { id: 'daily-209', question: 'Who was the first female Prime Minister of the UK?', answer: 'Margaret Thatcher', options: ['Margaret Thatcher', 'Theresa May', 'Angela Merkel', 'Indira Gandhi'], explanation: "Margaret Thatcher became the UK's first female Prime Minister in 1979 and served until 1990 — the longest consecutive tenure of any 20th-century British PM. Her economic policies (privatisation, union curbs, deregulation) became known as 'Thatcherism'; Angela Merkel was Germany's Chancellor, not British, and Indira Gandhi was India's Prime Minister." },
  { id: 'daily-210', question: 'Which ancient civilization built the Sphinx?', answer: 'Ancient Egyptians', options: ['Ancient Egyptians', 'Ancient Greeks', 'Mesopotamians', 'Nubians'], explanation: "The Great Sphinx of Giza was built by the ancient Egyptians around 2500 BC during the reign of Pharaoh Khafre, whose face it is believed to depict. It is the largest monolithic statue in the world, carved directly from the bedrock of the Giza Plateau — the nose was famously damaged, likely by Islamic soldiers using it for target practice in the 14th century." },

  // ── Science continued ────────────────────────────────────────────────────────
  { id: 'daily-211', question: 'What is the chemical symbol for silver?', answer: 'Ag', options: ['Ag', 'Si', 'Sr', 'Sn'], explanation: "Silver's symbol Ag comes from the Latin 'argentum.' The country Argentina is actually named after silver — Spanish conquistadors believed the region held vast silver deposits based on gifts they received from indigenous peoples; the name comes from the Latin/Italian word for silver." },
  { id: 'daily-212', question: 'Which planet is the hottest in our solar system?', answer: 'Venus', options: ['Venus', 'Mercury', 'Mars', 'Jupiter'], explanation: "Venus is the hottest planet at around 465°C despite being farther from the Sun than Mercury, because its thick atmosphere of CO₂ creates an extreme greenhouse effect that traps heat. Mercury, lacking any atmosphere, swings from 430°C in the day to -180°C at night — Venus maintains a stable, scorching temperature." },
  { id: 'daily-213', question: 'What is the study of earthquakes called?', answer: 'Seismology', options: ['Seismology', 'Geology', 'Volcanology', 'Tectonics'], explanation: "Seismology studies seismic waves produced by earthquakes, explosions, and other ground-shaking events. The Richter scale, developed by Charles Richter in 1935, measures earthquake magnitude; it has largely been replaced by the Moment Magnitude Scale (Mw) for scientific use, though the media still commonly refers to 'Richter scale' readings." },
  { id: 'daily-214', question: 'How many chambers does the human heart have?', answer: '4', options: ['4', '2', '3', '6'], explanation: "The human heart has four chambers: two atria (upper) and two ventricles (lower). The right side pumps deoxygenated blood to the lungs, while the left side pumps oxygenated blood to the rest of the body. Fish have a two-chambered heart, and amphibians have three — the four-chambered heart evolved in birds and mammals for more efficient circulation." },
  { id: 'daily-215', question: 'What is the most abundant element in Earth\'s crust?', answer: 'Oxygen', options: ['Oxygen', 'Silicon', 'Iron', 'Aluminum'], explanation: "Oxygen makes up about 46% of Earth's crust by mass — most of it bound in minerals like silicates and oxides rather than as breathable O₂. Silicon is the second most abundant at about 28%; the two together (as silicon dioxide and silicate minerals) form the vast majority of rocks and sand." },
  { id: 'daily-216', question: 'Which scientist discovered penicillin?', answer: 'Alexander Fleming', options: ['Alexander Fleming', 'Louis Pasteur', 'Joseph Lister', 'Edward Jenner'], explanation: "Alexander Fleming discovered penicillin in 1928 when he noticed that mould (Penicillium notatum) had contaminated a petri dish and was killing the surrounding bacteria. He published his findings but lacked the chemistry skills to develop it further; Howard Florey and Ernst Chain later purified it into a usable drug, and all three shared the 1945 Nobel Prize." },
  { id: 'daily-217', question: 'What type of rock is formed by volcanic activity?', answer: 'Igneous', options: ['Igneous', 'Sedimentary', 'Metamorphic', 'Limestone'], explanation: "Igneous rocks form when magma cools and solidifies — either underground (intrusive, like granite) or on the surface after a volcanic eruption (extrusive, like basalt). Sedimentary rocks form from compressed sediment layers, and metamorphic rocks form when existing rocks are transformed by heat and pressure — the three types make up the rock cycle." },
  { id: 'daily-218', question: 'What is the name of the process that converts sugar to alcohol?', answer: 'Fermentation', options: ['Fermentation', 'Distillation', 'Oxidation', 'Hydrolysis'], explanation: "Fermentation is carried out by yeast and some bacteria, which convert sugars into ethanol and carbon dioxide in the absence of oxygen. It is one of the oldest biotechnologies — humans have been making beer and wine through fermentation for at least 9,000 years, long before anyone understood the underlying chemistry." },
  { id: 'daily-219', question: 'Which organ filters blood in the human body?', answer: 'Kidneys', options: ['Kidneys', 'Liver', 'Spleen', 'Pancreas'], explanation: "The kidneys filter about 200 litres of blood per day, removing waste products and excess water to produce urine. The liver also performs filtering functions (processing toxins and drugs) but its primary role is metabolic rather than filtration; the spleen filters blood cells, removing old or damaged red blood cells." },
  { id: 'daily-220', question: 'How many elements are in the periodic table?', answer: '118', options: ['118', '112', '120', '108'], explanation: "The periodic table currently contains 118 confirmed elements, ending with oganesson (element 118). The first 94 occur naturally on Earth; elements 95–118 are synthetic and were created in nuclear reactors or particle accelerators. Scientists continue attempting to create elements 119 and 120." },

  // ── Sports continued ─────────────────────────────────────────────────────────
  { id: 'daily-221', question: 'What is the diameter of a basketball hoop in inches?', answer: '18 inches', options: ['18 inches', '16 inches', '20 inches', '15 inches'], explanation: "An NBA basketball hoop has an inner diameter of 18 inches (45.7 cm), while a standard basketball is about 9.4 inches in diameter — meaning the ball is roughly half the width of the hoop. This ratio is why skilled players can bank shots off the backboard and why a well-placed finger roll can drop straight through." },
  { id: 'daily-222', question: 'Which country has won the most Rugby World Cups?', answer: 'South Africa', options: ['South Africa', 'New Zealand', 'Australia', 'England'], explanation: "South Africa won its fourth Rugby World Cup in 2023, overtaking New Zealand (three titles) to become the most successful nation in the tournament's history. The Springboks' victories in 1995, 2007, 2019, and 2023 span different eras of the sport, with the 1995 win under Nelson Mandela's presidency carrying particular historical significance for post-apartheid South Africa." },
  { id: 'daily-223', question: 'In Formula 1, how many points does a race winner receive?', answer: '25', options: ['25', '20', '30', '10'], explanation: "The current F1 points system awards 25 points to the winner, down to 1 point for 10th place, plus a bonus point for the fastest lap (if the driver finishes in the top 10). The system has changed multiple times since F1's first season in 1950 — the old system awarded 9 points for a win, which is why comparing historical records requires context." },
  { id: 'daily-224', question: 'What is the highest possible score in a single turn in bowling?', answer: '300', options: ['300', '200', '270', '250'], explanation: "A perfect score of 300 in bowling requires 12 consecutive strikes in a single game (10 frames plus two bonus balls in the final frame). Each strike scores 10 plus the pins knocked down in the next two throws, so the scoring compounds — achieving 300 requires perfect execution on every single ball." },
  { id: 'daily-225', question: 'How long is an Olympic swimming pool?', answer: '50 metres', options: ['50 metres', '25 metres', '100 metres', '75 metres'], explanation: "Olympic swimming pools are 50 metres long (a 'long course' pool), while many recreational and competition pools are 25 metres ('short course'). World records are tracked separately for long course and short course swimming because swimmers perform slightly faster in short course pools due to the greater frequency of push-offs from the wall during turns." },
  { id: 'daily-226', question: 'Which country invented basketball?', answer: 'USA', options: ['USA', 'Canada', 'Germany', 'England'], explanation: "Basketball was invented in December 1891 by Dr. James Naismith — a Canadian physical education instructor working at a YMCA in Springfield, Massachusetts, USA. He needed an indoor winter activity and nailed peach baskets to a balcony railing; the sport spread rapidly and the US technically claims invention since that's where it was created." },
  { id: 'daily-227', question: 'How many players are on a volleyball team on the court?', answer: '6', options: ['6', '5', '7', '9'], explanation: "Each volleyball team has 6 players on the court at a time, in a 3-3 formation. Players rotate clockwise each time their team wins the serve. Beach volleyball, by contrast, uses just 2 players per team — a format added to the Olympics in 1996 that has become enormously popular." },
  { id: 'daily-228', question: 'What sport is played at the US Masters tournament?', answer: 'Golf', options: ['Golf', 'Tennis', 'Polo', 'Equestrian'], explanation: "The Masters Tournament is played annually at Augusta National Golf Club in Augusta, Georgia, and is one of golf's four major championships. Winners receive the iconic green jacket — a tradition started in 1949 — and former champions form an exclusive club that is invited to play each year." },
  { id: 'daily-229', question: 'Which country has won the most Cricket World Cups?', answer: 'Australia', options: ['Australia', 'West Indies', 'India', 'England'], explanation: "Australia has won the ICC Cricket World Cup (50-over format) six times — in 1987, 1999, 2003, 2007, 2015, and 2023. West Indies won the first two editions (1975 and 1979), establishing early dominance before Australia's era of supremacy. India won in 1983 and 2011, with England claiming their first title in 2019." },
  { id: 'daily-230', question: 'How many players are in a baseball team?', answer: '9', options: ['9', '10', '11', '8'], explanation: "A baseball team fields 9 players on defence, and the batting order also consists of 9 players. The American League introduced the designated hitter (DH) rule in 1973 — allowing a 10th player to bat in place of the pitcher — which became universal across Major League Baseball in 2022." },

  // ── Food & Drink continued ───────────────────────────────────────────────────
  { id: 'daily-231', question: 'Which country is the origin of pizza?', answer: 'Italy', options: ['Italy', 'Greece', 'USA', 'Turkey'], explanation: "Pizza originated in Naples, Italy, with the modern tomato-topped version developing in the 18th–19th centuries. The margherita pizza was reportedly created in 1889 for Queen Margherita of Savoy, using red tomato, white mozzarella, and green basil to represent the Italian flag — though some historians question whether this story is apocryphal." },
  { id: 'daily-232', question: 'What is the main ingredient in hummus?', answer: 'Chickpeas', options: ['Chickpeas', 'Lentils', 'Fava beans', 'White beans'], explanation: "'Hummus' literally means 'chickpeas' in Arabic — the full name 'hummus bi tahini' means 'chickpeas with tahini.' Its exact origins are disputed between several Middle Eastern countries, including Israel, Lebanon, and Palestine; the dish has been eaten across the region for centuries and any single-country claim of invention is contested." },
  { id: 'daily-233', question: 'Which country produces the most chocolate?', answer: 'Ivory Coast', options: ['Ivory Coast', 'Switzerland', 'Belgium', 'Ghana'], explanation: "Ivory Coast (Côte d'Ivoire) produces about 40–45% of the world's cocoa beans — the raw ingredient in chocolate. Switzerland and Belgium are famous for their chocolate manufacturing and quality, but they import their cocoa; the distinction between cocoa production (West Africa) and chocolate-making (Europe) is an important and often overlooked one." },
  { id: 'daily-234', question: 'What type of milk is traditionally used to make mozzarella?', answer: 'Buffalo milk', options: ['Buffalo milk', 'Cow milk', 'Goat milk', 'Sheep milk'], explanation: "Authentic mozzarella di bufala is made from the milk of water buffaloes and has protected geographical status in the EU. Most mass-produced mozzarella worldwide is made from cow's milk (fior di latte), which is cheaper and more widely available — buffalo milk mozzarella is richer, creamier, and noticeably different in flavour." },
  { id: 'daily-235', question: 'What is the national dish of England?', answer: 'Chicken tikka masala', options: ['Chicken tikka masala', 'Fish and chips', 'Roast beef', 'Shepherd\'s pie'], explanation: "Chicken tikka masala was declared Britain's national dish in 2001 by Foreign Secretary Robin Cook, reflecting the enormous influence of South Asian cuisine on British food culture. Its exact origin is disputed — some say it was invented in Glasgow or Birmingham by Bangladeshi or Indian chefs adapting the dish for British tastes by adding a creamy tomato sauce." },
  { id: 'daily-236', question: 'Which fruit is used to make wine?', answer: 'Grape', options: ['Grape', 'Apple', 'Plum', 'Apricot'], explanation: "Wine is made from fermented grapes — specifically varieties of Vitis vinifera, the European wine grape. Other fruits can also be fermented into wine (apple cider, plum wine, etc.) but are not typically called 'wine' without a qualifier. Grapes became dominant for winemaking partly because their natural sugar content and acidity are ideal for fermentation." },
  { id: 'daily-237', question: 'What is tofu made from?', answer: 'Soybeans', options: ['Soybeans', 'Rice', 'Chickpeas', 'Peas'], explanation: "Tofu is made by coagulating soy milk and pressing the curds into solid blocks — essentially the same process as cheesemaking. It originated in China around 200 BC and spread throughout East and Southeast Asia. Its bland flavour makes it highly versatile; it absorbs marinades and sauces readily, making it a protein staple in vegetarian and vegan diets." },
  { id: 'daily-238', question: 'Which country is famous for its kimchi?', answer: 'South Korea', options: ['South Korea', 'Japan', 'China', 'Vietnam'], explanation: "Kimchi is a traditional Korean dish of salted and fermented vegetables — most commonly napa cabbage — seasoned with chilli pepper, garlic, and ginger. It is so central to Korean identity that UNESCO added it to its Intangible Cultural Heritage list in 2013. The average South Korean eats around 18 kg of kimchi per year." },
  { id: 'daily-239', question: 'What is the primary ingredient in a traditional Caesar salad dressing?', answer: 'Anchovy', options: ['Anchovy', 'Parmesan', 'Lemon', 'Garlic'], explanation: "Traditional Caesar dressing is built around anchovy (often as Worcestershire sauce or paste), egg yolk, lemon juice, garlic, and Parmesan. The salad was invented in 1924 by Caesar Cardini, an Italian immigrant who ran a restaurant in Tijuana, Mexico — notably, his original recipe did not include anchovies, which were added by others later." },
  { id: 'daily-240', question: 'Which nut is used to make Nutella?', answer: 'Hazelnut', options: ['Hazelnut', 'Almond', 'Peanut', 'Walnut'], explanation: "Nutella is made primarily from sugar and palm oil, with hazelnuts making up about 13% of the product — more than cocoa (7.4%). It was created by Pietro Ferrero in Italy in 1964 as an affordable chocolate spread during cocoa shortages; the Ferrero family became one of Italy's wealthiest, with the spread now consuming roughly a quarter of the world's hazelnut supply." },

  // ── Animals & Nature ─────────────────────────────────────────────────────────
  { id: 'daily-241', question: 'What is the fastest land animal?', answer: 'Cheetah', options: ['Cheetah', 'Lion', 'Greyhound', 'Pronghorn antelope'], explanation: "Cheetahs can accelerate from 0 to 100 km/h in about 3 seconds and reach top speeds of 112–120 km/h, making them the fastest land animals. However, they can only maintain this speed for 20–30 seconds before overheating; the pronghorn antelope is actually the fastest animal over sustained distances, reaching 88 km/h for miles." },
  { id: 'daily-242', question: 'How long is an elephant\'s pregnancy?', answer: '22 months', options: ['22 months', '12 months', '18 months', '9 months'], explanation: "Elephants have the longest gestation period of any land animal at approximately 22 months — nearly two years. This extended pregnancy allows elephant calves to develop large, complex brains before birth; newborn elephants can walk within hours and have already developed enough intelligence to begin learning from their herd." },
  { id: 'daily-243', question: 'What is the largest animal ever to have lived?', answer: 'Blue whale', options: ['Blue whale', 'African elephant', 'Diplodocus', 'Sperm whale'], explanation: "The blue whale is the largest animal ever known to have existed on Earth, reaching up to 30 metres in length and 180 tonnes — heavier than any dinosaur. Its heart alone can weigh as much as a car, and its call is the loudest sound produced by any animal, detectable by other whales hundreds of kilometres away." },
  { id: 'daily-244', question: 'How many legs does a spider have?', answer: '8', options: ['8', '6', '10', '12'], explanation: "Spiders have 8 legs — a defining feature of arachnids, which distinguishes them from insects (6 legs). Spiders also have 8 eyes in most species, though the arrangement and functionality varies widely; some jumping spiders have extraordinary forward-facing eyes with nearly human-like visual acuity for their size." },
  { id: 'daily-245', question: 'What is a group of lions called?', answer: 'Pride', options: ['Pride', 'Pack', 'Herd', 'Colony'], explanation: "A group of lions is called a pride, typically consisting of related females, their cubs, and a small number of adult males. Lions are the only truly social cats — all other big cat species are largely solitary. Female lions do most of the hunting while males primarily defend the pride's territory." },
  { id: 'daily-246', question: 'Which bird lays the largest eggs?', answer: 'Ostrich', options: ['Ostrich', 'Emu', 'Albatross', 'Pelican'], explanation: "Ostrich eggs are the largest of any living bird, weighing up to 1.4 kg and measuring about 15 cm long. Despite being the largest eggs, they are actually the smallest relative to the size of the mother — a hummingbird's egg is proportionally about six times larger relative to its body." },
  { id: 'daily-247', question: 'What is the only mammal capable of true flight?', answer: 'Bat', options: ['Bat', 'Flying squirrel', 'Sugar glider', 'Colugo'], explanation: "Bats are the only mammals capable of sustained, powered flight — flying squirrels, sugar gliders, and colugos glide but cannot generate lift. There are over 1,400 species of bats, making up about 20% of all mammal species. Most use echolocation to navigate and hunt in darkness, emitting ultrasonic calls and interpreting the returning echoes." },
  { id: 'daily-248', question: 'How many eyes does a bee have?', answer: '5', options: ['5', '2', '3', '4'], explanation: "Bees have 5 eyes — two large compound eyes on the sides of their head (which detect colour and movement) and three small simple eyes (ocelli) on top that detect light intensity and help with navigation. The compound eyes can see ultraviolet light, which humans cannot, revealing patterns on flowers invisible to us that guide bees to nectar." },
  { id: 'daily-249', question: 'What is the name of a baby kangaroo?', answer: 'Joey', options: ['Joey', 'Cub', 'Foal', 'Pup'], explanation: "A baby kangaroo is called a joey. At birth, joeys are incredibly undeveloped — about the size of a jellybean — and immediately crawl into their mother's pouch to continue development. They spend approximately six months in the pouch before beginning to venture out, returning to the pouch for warmth and safety for several more months." },
  { id: 'daily-250', question: 'Which is the only continent with no native reptile species?', answer: 'Antarctica', options: ['Antarctica', 'Arctic', 'Iceland', 'Greenland'], explanation: "Antarctica has no native reptile species because reptiles are ectotherms (cold-blooded) and cannot survive the continent's extreme cold. The Arctic is not a continent — it's an ocean covered by sea ice — and both Iceland and Greenland are islands. Antarctica's only vertebrate residents are birds (penguins, petrels) and marine mammals." },
  { id: 'daily-251', question: 'What colour is a polar bear\'s skin?', answer: 'Black', options: ['Black', 'White', 'Pink', 'Transparent'], explanation: "Polar bears have black skin beneath their fur, which helps absorb heat from sunlight. Their fur appears white but is actually translucent and hollow — the optical properties of the hollow shafts scatter and reflect visible light, producing the white appearance. A polar bear with algae growing in its fur can temporarily appear green." },
  { id: 'daily-252', question: 'How many arms does a starfish typically have?', answer: '5', options: ['5', '4', '6', '8'], explanation: "Most starfish (sea stars) have 5 arms, reflecting their pentaradial (five-fold) symmetry — they have no front or back, and can move in any direction. Some species have more arms: the sun star can have up to 24. Remarkably, starfish can regenerate lost arms, and in some species a single severed arm can regrow an entirely new body." },
  { id: 'daily-253', question: 'What is the largest species of big cat?', answer: 'Tiger', options: ['Tiger', 'Lion', 'Jaguar', 'Leopard'], explanation: "Tigers are the largest wild cat species, with Siberian (Amur) tigers being the biggest subspecies — males can weigh over 300 kg and measure more than 3 metres in length. Unlike lions, tigers are solitary hunters and are the only big cats that love water and are strong swimmers, often cooling off in rivers and streams." },
  { id: 'daily-254', question: 'What do caterpillars turn into?', answer: 'Butterflies or moths', options: ['Butterflies or moths', 'Beetles', 'Flies', 'Grasshoppers'], explanation: "Caterpillars are the larval stage of butterflies and moths (order Lepidoptera). Inside the chrysalis (butterfly) or cocoon (moth), the caterpillar's body essentially dissolves and reorganises into the adult form — a process called metamorphosis. The adult butterfly or moth that emerges is genetically identical but completely restructured." },
  { id: 'daily-255', question: 'Which animal has the longest lifespan?', answer: 'Greenland shark', options: ['Greenland shark', 'Giant tortoise', 'Bowhead whale', 'Koi fish'], explanation: "Greenland sharks can live over 400 years, making them the longest-lived vertebrate known to science. Scientists date them by measuring radiocarbon in their eye lenses — one individual was estimated at 392 ± 120 years old, potentially born before the Mayflower landed in America. They grow only 1 cm per year." },
  { id: 'daily-256', question: 'How many bones does a shark have?', answer: '0', options: ['0', '200', '100', '50'], explanation: "Sharks have no bones — their skeletons are made entirely of cartilage, the same flexible tissue in human ears and noses. Cartilage is lighter and more flexible than bone, which helps sharks stay buoyant and manoeuvre quickly. Because cartilage rarely fossilises, the shark fossil record consists mostly of teeth." },
  { id: 'daily-257', question: 'What is the largest species of penguin?', answer: 'Emperor penguin', options: ['Emperor penguin', 'King penguin', 'Macaroni penguin', 'Gentoo penguin'], explanation: "Emperor penguins stand about 1.2 metres tall and weigh up to 40 kg — the tallest and heaviest of all penguin species. They breed in Antarctica during winter, with males incubating the egg on their feet under a brood pouch for about 65 days without eating while females hunt at sea, enduring temperatures as low as -60°C." },
  { id: 'daily-258', question: 'Which animal sleeps the most hours per day on average?', answer: 'Koala', options: ['Koala', 'Sloth', 'Cat', 'Lion'], explanation: "Koalas sleep 18–22 hours per day because their diet of eucalyptus leaves is extremely low in nutrition and takes enormous energy to digest. Eucalyptus leaves are also toxic to most animals; koalas have specialised gut bacteria and an extra-long digestive tract to neutralise the toxins, a process that is metabolically demanding." },
  { id: 'daily-259', question: 'What is a group of wolves called?', answer: 'Pack', options: ['Pack', 'Pride', 'Herd', 'Flock'], explanation: "A group of wolves is called a pack, typically consisting of a mated pair (the alphas) and their offspring from multiple years. The alpha male/female terminology has been revised by wolf researchers — studies of wild wolves show packs are simply family units, and the 'alpha' concept came from observations of unrelated captive wolves competing abnormally." },
  { id: 'daily-260', question: 'Which insect pollinates most of the world\'s crops?', answer: 'Bee', options: ['Bee', 'Butterfly', 'Wasp', 'Moth'], explanation: "Bees are the most important pollinators of food crops, responsible for pollinating roughly one-third of the food humans eat. The decline of bee populations due to pesticides, habitat loss, and disease is considered a serious threat to global food security. Some crops in China are now hand-pollinated by humans because local bee populations have collapsed." },

  // ── Mixed General Knowledge ──────────────────────────────────────────────────
  { id: 'daily-261', question: 'What is the currency of Japan?', answer: 'Yen', options: ['Yen', 'Won', 'Yuan', 'Ringgit'], explanation: "The Japanese yen (¥) has been Japan's currency since 1871. The Won is South Korea's currency, the Yuan (or Renminbi) is China's, and the Ringgit is Malaysia's. Japan's yen is one of the world's most traded currencies and is often used as a 'safe haven' asset during global financial crises." },
  { id: 'daily-262', question: 'How many sides does a hexagon have?', answer: '6', options: ['6', '5', '7', '8'], explanation: "A hexagon has 6 sides. Hexagons appear extensively in nature — most famously in honeycomb, where bees build hexagonal cells because the shape is the most efficient way to pack equal-sized compartments with the least amount of wax. This efficiency is why hexagons also appear in basalt columns and insect compound eyes." },
  { id: 'daily-263', question: 'What is the largest planet in our solar system?', answer: 'Jupiter', options: ['Jupiter', 'Saturn', 'Uranus', 'Neptune'], explanation: "Jupiter is so large that all other planets in the solar system could fit inside it with room to spare. Its Great Red Spot is a storm that has been raging for at least 350 years — though it has been gradually shrinking. Jupiter's immense gravity also acts as a shield, pulling comets and asteroids away from the inner solar system." },
  { id: 'daily-264', question: 'In which year was the first iPhone released?', answer: '2007', options: ['2007', '2005', '2008', '2010'], explanation: "Steve Jobs announced the original iPhone on January 9, 2007, calling it 'a revolutionary product that changes everything.' Nokia and BlackBerry executives dismissed it as impractical — a misjudgement that contributed to both companies' dramatic collapse within a decade, as the iPhone redefined what a mobile phone could be." },
  { id: 'daily-265', question: 'How many days are in a leap year?', answer: '366', options: ['366', '365', '367', '364'], explanation: "A leap year has 366 days, with the extra day added as February 29. It occurs every four years to correct for the fact that a solar year is approximately 365.25 days. The rule has exceptions — years divisible by 100 are not leap years unless also divisible by 400, which is why 2000 was a leap year but 1900 was not." },
  { id: 'daily-266', question: 'What is the currency of the European Union?', answer: 'Euro', options: ['Euro', 'Pound', 'Franc', 'Mark'], explanation: "The euro was introduced as an electronic currency in 1999 and as physical coins and notes in 2002. Not all EU members use it — notably the UK (which left the EU), Sweden, Denmark, Poland, Czech Republic, and Hungary retain their own currencies. The eurozone currently consists of 20 of the 27 EU member states." },
  { id: 'daily-267', question: 'What is the square root of 144?', answer: '12', options: ['12', '14', '11', '13'], explanation: "The square root of 144 is 12, since 12 × 12 = 144. 144 is also a 'perfect square' — a number that is the square of an integer — and equals 12². In the Fibonacci sequence, 144 is the largest Fibonacci number that is also a perfect square, a mathematical distinction that appears in studies of number theory." },
  { id: 'daily-268', question: 'How many hours are in a week?', answer: '168', options: ['168', '144', '196', '172'], explanation: "A week has 7 days × 24 hours = 168 hours. The seven-day week was established in ancient Mesopotamia and adopted by Romans, with each day named after a celestial body — the Sun (Sunday), Moon (Monday), Mars (Tuesday in Romance languages), Mercury (Wednesday), Jupiter (Thursday), Venus (Friday), and Saturn (Saturday)." },
  { id: 'daily-269', question: 'What is the national animal of Australia?', answer: 'Kangaroo', options: ['Kangaroo', 'Koala', 'Platypus', 'Emu'], explanation: "Australia has two national animals: the red kangaroo and the emu. Both appear on the Australian coat of arms — supposedly chosen because neither can walk backwards, symbolising a nation always moving forward. The kangaroo is more commonly cited as the national animal; the koala and platypus are iconic but hold no official national status." },
  { id: 'daily-270', question: 'Which planet is closest to the Sun?', answer: 'Mercury', options: ['Mercury', 'Venus', 'Earth', 'Mars'], explanation: "Mercury is the closest planet to the Sun at an average distance of 57.9 million km, orbiting it in just 88 Earth days. Despite being the closest, it is not the hottest planet (that's Venus) because it has no atmosphere to trap heat; surface temperatures swing from 430°C on the day side to -180°C on the night side." },
  { id: 'daily-271', question: 'How many strings does a violin have?', answer: '4', options: ['4', '6', '5', '3'], explanation: "A violin has 4 strings tuned G-D-A-E from lowest to highest. It is the smallest and highest-pitched member of the orchestral string family, which also includes the viola (also 4 strings, tuned lower: C-G-D-A), cello, and double bass. Violin technique took centuries to fully develop, reaching its classical peak with composers like Vivaldi and Paganini." },
  { id: 'daily-272', question: 'What is the national flower of Japan?', answer: 'Cherry blossom', options: ['Cherry blossom', 'Chrysanthemum', 'Lotus', 'Peony'], explanation: "The cherry blossom (sakura) is Japan's unofficial national flower and a profound cultural symbol representing the transience of life — its blooms last only 1–2 weeks. Hanami (flower viewing) festivals have been celebrated for over 1,000 years. The chrysanthemum is the imperial seal of Japan's royal family, so both have strong national significance." },
  { id: 'daily-273', question: 'What is the chemical symbol for sodium?', answer: 'Na', options: ['Na', 'So', 'Sd', 'Nm'], explanation: "Sodium's symbol Na comes from the Latin 'natrium' — which in turn came from the Egyptian word for a type of salt (natron). Table salt is sodium chloride (NaCl). Sodium is a highly reactive metal that explodes on contact with water; it is essential for nerve function and fluid balance in the human body." },
  { id: 'daily-274', question: 'How many strings does a standard ukulele have?', answer: '4', options: ['4', '6', '8', '5'], explanation: "A standard ukulele has 4 strings, typically tuned G-C-E-A. The ukulele originated in Hawaii in the 1880s, adapted from the Portuguese machete instrument brought by immigrant workers. The name is believed to mean 'jumping flea' in Hawaiian — possibly referring to the rapid finger movements of players." },
  { id: 'daily-275', question: 'What does "Wi-Fi" stand for?', answer: 'Wireless Fidelity', options: ['Wireless Fidelity', 'Wide Frequency', 'Wireless Frequency Interface', 'Wide Field Internet'], explanation: "Wi-Fi stands for Wireless Fidelity, though the term was actually coined as a marketing phrase by the brand consulting firm Interbrand without a technical meaning. The underlying technology is based on the IEEE 802.11 standards. The key patents behind Wi-Fi were largely developed by Australia's CSIRO, earning Australia hundreds of millions in royalties." },
  { id: 'daily-276', question: 'In which country was the sport of polo invented?', answer: 'Persia', options: ['Persia', 'England', 'Argentina', 'India'], explanation: "Polo originated in ancient Persia (modern Iran) around 2,500 years ago, initially as training for cavalry units. It spread through Central Asia and was brought to Britain by soldiers returning from India in the 19th century, where it gained its aristocratic reputation. Argentina is now arguably the world's dominant polo nation in terms of high-goal competition." },
  { id: 'daily-277', question: 'What colour is a ruby?', answer: 'Red', options: ['Red', 'Blue', 'Green', 'Purple'], explanation: "Rubies are red gemstones made of the mineral corundum (aluminium oxide) with chromium impurities giving them their red colour. The same mineral in different colours is called sapphire — blue, yellow, pink, and even white corundum are all sapphires, but only the red variety is called a ruby. The finest rubies come from Myanmar (Burma)." },
  { id: 'daily-278', question: 'Which element is a diamond made of?', answer: 'Carbon', options: ['Carbon', 'Silicon', 'Quartz', 'Nitrogen'], explanation: "Diamonds are pure carbon atoms arranged in a crystal lattice — the same element as graphite (pencil lead) and charcoal, just with different atomic bonding. This structural difference gives diamond extraordinary hardness while graphite is soft and slippery. Diamonds form under extreme heat and pressure about 150 km beneath Earth's surface." },
  { id: 'daily-279', question: 'What is the fear of spiders called?', answer: 'Arachnophobia', options: ['Arachnophobia', 'Entomophobia', 'Zoophobia', 'Insectophobia'], explanation: "Arachnophobia — from the Greek 'arachne' (spider) and 'phobos' (fear) — is one of the most common specific phobias, affecting up to 6% of the population. Entomophobia is fear of insects (spiders are not insects), and zoophobia is a general fear of animals. Some researchers believe spider phobia has evolutionary roots, as spiders were a genuine danger to early humans." },
  { id: 'daily-280', question: 'How many teeth does an adult human have?', answer: '32', options: ['32', '28', '30', '34'], explanation: "Adult humans have 32 teeth, including 4 wisdom teeth (third molars). Many people have their wisdom teeth removed because modern jaws are often too small to accommodate them comfortably — a mismatch between our ancient dental biology and the smaller jaws that evolved with our diet of softer, cooked food." },
  { id: 'daily-281', question: 'What is the national sport of Canada?', answer: 'Lacrosse and ice hockey', options: ['Lacrosse and ice hockey', 'Ice hockey', 'Curling', 'Football'], explanation: "Canada officially recognises two national sports: lacrosse (summer) and ice hockey (winter), established by the National Sports of Canada Act in 1994. Lacrosse was played by Indigenous peoples for centuries before European contact. While ice hockey dominates Canadian cultural identity, the dual designation acknowledges the sport's Indigenous heritage." },
  { id: 'daily-282', question: 'Which gas is responsible for the greenhouse effect?', answer: 'Carbon dioxide', options: ['Carbon dioxide', 'Oxygen', 'Methane', 'Nitrogen'], explanation: "Carbon dioxide (CO₂) is the primary driver of the human-caused greenhouse effect, though methane is a more potent greenhouse gas molecule-for-molecule (about 80 times more warming over 20 years). CO₂ matters most because of the massive quantities released by burning fossil fuels — it accumulates in the atmosphere and persists for centuries." },
  { id: 'daily-283', question: 'What is the largest organ inside the human body?', answer: 'Liver', options: ['Liver', 'Lungs', 'Heart', 'Brain'], explanation: "The liver is the largest internal organ, weighing about 1.4 kg. It performs over 500 functions including detoxifying blood, producing bile for digestion, metabolising drugs and alcohol, and producing proteins essential for blood clotting. Skin is the largest organ overall but is external; the liver holds the internal record." },
  { id: 'daily-284', question: 'How many time zones does Russia span?', answer: '11', options: ['11', '9', '12', '8'], explanation: "Russia spans 11 time zones — more than any other country in the world. When it is midnight in Kaliningrad (the westernmost part), it is already past 10am the next day on the Kamchatka Peninsula in the far east. The US spans 6 time zones including non-contiguous territories, and Canada spans 6 as well." },
  { id: 'daily-285', question: 'What is the name of the world\'s largest coral reef system?', answer: 'Great Barrier Reef', options: ['Great Barrier Reef', 'Belize Barrier Reef', 'Red Sea Reef', 'Mesoamerican Reef'], explanation: "Australia's Great Barrier Reef stretches over 2,300 km and is the world's largest coral reef system, visible from space. It supports an estimated 9,000 species and is a UNESCO World Heritage Site. Climate change-driven ocean warming has caused repeated mass bleaching events — the reef lost about 50% of its coral between 1995 and 2017." },
  { id: 'daily-286', question: 'Which country has the most volcanoes?', answer: 'Indonesia', options: ['Indonesia', 'Japan', 'USA', 'Philippines'], explanation: "Indonesia sits on the 'Ring of Fire' and has approximately 130 active volcanoes — more than any other country. The 1815 eruption of Mount Tambora in Indonesia was the largest volcanic eruption in recorded history, causing the 'Year Without a Summer' in 1816 when ash blocked sunlight globally, causing crop failures and famines across the Northern Hemisphere." },
  { id: 'daily-287', question: 'What is the capital of Sweden?', answer: 'Stockholm', options: ['Stockholm', 'Oslo', 'Copenhagen', 'Helsinki'], explanation: "Stockholm is Sweden's capital and largest city, built across 14 islands where Lake Mälaren meets the Baltic Sea. Oslo is Norway's capital, Copenhagen is Denmark's, and Helsinki is Finland's — all Nordic capitals that are sometimes confused. Stockholm has been Sweden's capital since the 13th century." },
  { id: 'daily-288', question: 'How many keys does a standard piano have?', answer: '88', options: ['88', '76', '92', '84'], explanation: "A standard piano has 88 keys — 52 white and 36 black — spanning just over 7 octaves. Early pianos had fewer keys; composers like Beethoven gradually pushed manufacturers to extend the range as his compositions demanded notes beyond the instrument's limits. The 88-key standard was established in the late 19th century." },
  { id: 'daily-289', question: 'What is the national symbol of Canada?', answer: 'Maple leaf', options: ['Maple leaf', 'Beaver', 'Moose', 'Loon'], explanation: "The maple leaf is Canada's most prominent national symbol, appearing on the national flag since 1965. The beaver is Canada's official national animal (since 1975) — it was central to the fur trade that drove early colonisation. The loon appears on the Canadian dollar coin, earning the coin its nickname 'the loonie.'" },
  { id: 'daily-290', question: 'Which planet rotates on its side?', answer: 'Uranus', options: ['Uranus', 'Neptune', 'Saturn', 'Venus'], explanation: "Uranus has an axial tilt of about 98 degrees — meaning it essentially rotates on its side relative to its orbit. This extreme tilt likely resulted from a massive collision early in the solar system's history. During Uranus's 84-year orbit, each pole experiences 42 years of continuous sunlight followed by 42 years of darkness." },
  { id: 'daily-291', question: 'What is the most visited city in the world?', answer: 'Bangkok', options: ['Bangkok', 'Paris', 'London', 'Dubai'], explanation: "Bangkok (officially Krung Thep Maha Nakhon) consistently ranks as the world's most visited city by international visitors according to Mastercard's Global Destination Cities Index, receiving over 22 million tourists annually pre-pandemic. Paris is often assumed to be #1 due to its cultural fame, but Bangkok's combination of affordability, temples, street food, and nightlife draws more visitors." },
  { id: 'daily-292', question: 'How many bones are in the human spine?', answer: '33', options: ['33', '26', '30', '24'], explanation: "The human spine has 33 vertebrae at birth, but in adults the lower vertebrae fuse together — the 5 sacral vertebrae fuse into the sacrum and the 4 coccygeal vertebrae fuse into the coccyx — resulting in 26 movable units in adults. Both 33 and 26 can be correct depending on the context of the question." },
  { id: 'daily-293', question: 'What is the freezing point of water in Fahrenheit?', answer: '32°F', options: ['32°F', '0°F', '100°F', '212°F'], explanation: "Water freezes at 32°F (0°C) and boils at 212°F (100°C). The Fahrenheit scale was defined by Daniel Gabriel Fahrenheit in 1724 using three reference points including the freezing temperature of brine. The Celsius scale, defined later using water's freezing and boiling points as 0 and 100, is more intuitive and used by most of the world." },
  { id: 'daily-294', question: 'Which country is the world\'s largest producer of wine?', answer: 'Italy', options: ['Italy', 'France', 'Spain', 'USA'], explanation: "Italy and France regularly trade the top spot for wine production, with Italy most often leading by volume. Italy produces a staggering variety of wine styles across its 20 regions — from Barolo in Piedmont to Chianti in Tuscany to Amarone in Veneto — with over 350 officially recognised indigenous grape varieties." },
  { id: 'daily-295', question: 'What is the name of the river that runs through Rome?', answer: 'Tiber', options: ['Tiber', 'Po', 'Arno', 'Adige'], explanation: "The Tiber (Tevere) runs approximately 406 km through central Italy, passing through Rome before emptying into the Tyrrhenian Sea. Ancient Rome grew beside the Tiber because it provided fresh water, a trading route, and a natural defence; the river flooded regularly until modern embankments were built in the 19th century." },
  { id: 'daily-296', question: 'How many degrees are in a right angle?', answer: '90', options: ['90', '45', '180', '60'], explanation: "A right angle is exactly 90 degrees — one quarter of a full 360-degree rotation. The degree system dividing circles into 360 parts dates to ancient Babylon, which used a base-60 number system. A straight angle is 180°, a full rotation is 360°, and 45° is half a right angle (found in isosceles right triangles)." },
  { id: 'daily-297', question: 'Which country has the most spoken languages?', answer: 'Papua New Guinea', options: ['Papua New Guinea', 'Indonesia', 'India', 'Nigeria'], explanation: "Papua New Guinea has over 840 living languages — more than any other country — spoken by a population of only about 10 million people. This extraordinary linguistic diversity reflects the country's mountainous terrain, which kept communities isolated from each other for thousands of years, allowing distinct languages to evolve independently." },
  { id: 'daily-298', question: 'What is the tallest type of grass?', answer: 'Bamboo', options: ['Bamboo', 'Sugarcane', 'Corn', 'Pampas grass'], explanation: "Bamboo is botanically a grass — the world's tallest, with some species reaching over 30 metres and growing up to 91 cm in a single day (the fastest growing plant on Earth). Despite its wood-like appearance and strength (used in construction), bamboo is a true member of the grass family Poaceae." },
  { id: 'daily-299', question: 'Which country has the most islands?', answer: 'Sweden', options: ['Sweden', 'Finland', 'Norway', 'Indonesia'], explanation: "Sweden has approximately 221,800 islands — more than any other country when all sizes are counted, due to its extensive archipelagos along the Baltic and North Sea coasts. Indonesia is often cited as having the most islands by landmass and population importance, but Sweden wins on raw island count." },
  { id: 'daily-300', question: 'What is the only letter not appearing on the periodic table?', answer: 'J', options: ['J', 'Q', 'X', 'Z'], explanation: "The letter J does not appear in any element's symbol on the periodic table — making it the only letter entirely absent. Q and X appear in element names (e.g. Xenon = Xe), Z appears in symbols like Zinc (Zn) and Zirconium (Zr), but J has never been used in any element name or symbol throughout the periodic table's history." },
];
